window.SCENES = {"prologue": [{"t": "bg", "bg": "長安・相国府／大広間（夜・燭台の海）", "mood": "warm"}, {"t": "narrate", "text": "酒が、旨い。"}, {"t": "narrate", "text": "旨いのは、これがわしの酒だからだ。わしが奪った都の、わしが据えた天子の、わしが立てた秩序の上で飲む酒だからだ。"}, {"t": "sprite", "key": "dongzhuo_menace", "pos": "center"}, {"t": "narrate", "text": "大広間に並んだ公卿どもの背中を見ろ。みな揃って、わしに尻を向けて拝んでいる。三公九卿、累代の名門、清流だの名士だの——血筋を首から下げて歩く連中だ。"}, {"t": "narrate", "text": "そいつらが、いつ民の腹を満たした。礼だ仁だと囀る口で、宦官に媚び、外戚に這いつくばり、官位を金で売り買いし、洛陽を百年かけて腐らせた。奪わぬ顔で奪い、殺さぬ顔で殺してきた。"}, {"t": "narrate", "text": "わしは違う。殺すと言って殺す。奪うと言って奪う。それだけだ。"}, {"t": "say", "name": "董卓", "text": "礼だ仁だと囀る口が、いつ民の腹を満たした。わしの刀は一度も飢えさせたことはないぞ"}, {"t": "narrate", "text": "涼州の風の中で、わしは羌の豪帥どもの懐に入った。牛を屠って喰わせ、賜った絹は一匹残らず兵に分けた。六軍が崩れる中、わしの軍だけが一兵も欠かさず帰ってきた。あれが力だ。あれが正しさだ。"}, {"t": "narrate", "text": "玉座が腐っているなら、腐った木は薪にくべるが道理だろう。わしは火だ。文句があるなら、燃えてみせろ。"}, {"t": "sprite", "key": "dongzhuo_base", "pos": "center"}, {"t": "narrate", "text": "——と、列の中から一人、進み出てきた爺がいる。司徒・王允。"}, {"t": "sprite", "key": "wangyun_base", "pos": "left"}, {"t": "narrate", "text": "舌の上で言葉を転がすのが好きな手合いだ。わしはこの種の声を聞くと、屠る前の豚の鳴き声を思い出す。やかましくて、中身がなくて、最後はこっちの腹を満たす。"}, {"t": "say", "name": "王允", "text": "相国閣下。長安に新たな世が立ちましたること、この王允、感服のほかございませぬ。つきましては——卑しき身ながら、恭順の証として、献じたきものがございます"}, {"t": "narrate", "text": "ほう。"}, {"t": "say", "name": "董卓", "text": "証だと。爺、お前の忠義など、その皺の数ほど安いと思っていたがな。何を寄越す"}, {"t": "say", "name": "王允", "text": "これに"}, {"t": "fx", "fx": "letterbox"}, {"t": "sprite", "key": "wangyun_scheme", "pos": "left"}, {"t": "say", "name": "王允", "text": "賤しき養女にございます。歌舞を少々。名を——貂蝉と"}, {"t": "narrate", "text": "賤しい、だと。爺の声が、その一言だけ湿った。嘘だな。三十年、人の嘘を嗅いできた鼻が言っている。この爺、この女を本気で惜しんでいる。惜しいものを差し出す。——なら、これは賄賂ではない。"}, {"t": "narrate", "text": "罠だ。"}, {"t": "narrate", "text": "分かっていて、わしは盃を置かなかった。"}, {"t": "fx", "fx": "flash"}, {"t": "fx", "fx": "blackout"}, {"t": "fx", "fx": "cutin"}, {"t": "sprite", "key": "diaochan_base", "pos": "center"}, {"t": "narrate", "text": "女が、来た。"}, {"t": "narrate", "text": "薄絹の襦裙が燭の海を泳ぐように揺れ、披帛が宙に尾を引く。簪が光り、歩揺が鳴る。腰、足首、首の傾げかた——女ってのは値札を首から下げて歩いてるようなものだ。高い女ほど安く見せ、安い女ほど高く見せたがる。"}, {"t": "narrate", "text": "こいつは、どっちでもなかった。"}, {"t": "sprite", "key": "diaochan_fakesmile", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "貂蝉と申します。……相国さまの御前に侍れますこと、身に余る誉れにございます"}, {"t": "narrate", "text": "完璧に微笑みおった。——完璧すぎる。一分の狂いもない笑みだ。"}, {"t": "narrate", "text": "その目の奥だけが、笑っておらん。"}, {"t": "narrate", "text": "媚びながら、わしを値踏みしておる。——いい度胸だ。"}, {"t": "narrate", "text": "面白い。"}, {"t": "sprite", "key": "diaochan_killerlove", "pos": "center"}, {"t": "narrate", "text": "女が酌をしようと、しなだれかかってくる。盃を満たす指が、わしの手の甲をかすめる寸前で——止まった。止めたのは、女のほうだ。触れるか触れぬかの一寸を、こいつは支配している。"}, {"t": "say", "name": "貂蝉", "text": "……お注ぎいたしましょうか。それとも"}, {"t": "narrate", "text": "吐息の距離で、女が見上げてくる。"}, {"t": "say", "name": "貂蝉", "text": "妾の手より、酒のほうがお好みでいらっしゃる?"}, {"t": "narrate", "text": "隣で、李儒が袖を引いた。"}, {"t": "sprite", "key": "liju_remonstrate", "pos": "right"}, {"t": "say", "name": "李儒", "text": "（太師。あの献じられかた、美しすぎます。……お気をつけを）"}, {"t": "narrate", "text": "言われんでも分かっておる。——だが、お前の目は確かだ、李儒。"}, {"t": "sprite", "key": "dongzhuo_menace", "pos": "center"}, {"t": "narrate", "text": "さて。——この女に、どう応えてやろうか。"}, {"t": "choice", "options": [{"text": "「面白い。お前が何者か、暴いてやる」と、女の目の奥を見据える", "d": {"diaochan": 2, "roken": 1}, "goto": "prologue_a"}, {"text": "「よく来てくれた。不自由はさせぬ。今日からここがお前の家だ」と優しく労う", "d": {"diaochan": -2}, "goto": "prologue_b"}, {"text": "「女など褒美の一つだ」と一瞥もくれず、顎で傍に侍らせる", "d": {"diaochan": -1, "rogan": 1}, "goto": "prologue_c"}]}], "prologue_a": [{"t": "say", "name": "董卓", "text": "面白い。——酒の味なら、もう三十年知っている。わしが知らんのはお前のほうだ、貂蝉"}, {"t": "narrate", "text": "わしは盃を置いた。初めてのことだ。"}, {"t": "say", "name": "董卓", "text": "女が無傷でわしの間合いに入る理由は、二つに一つだ。商売か、刺客か。お前は——両方の匂いがする。ならば暴いてやろう。その刃ごと、お前が何者か、わしが暴いてやる"}, {"t": "sprite", "key": "diaochan_flustered", "pos": "center"}, {"t": "narrate", "text": "女の微笑みが、固まった。ほんの一瞬。睫毛の影が、震えた。"}, {"t": "narrate", "text": "——見えたぞ。仕込まれた笑みの下の、生身の女が。"}, {"t": "say", "name": "貂蝉", "text": "……まあ。妾を、抱くのではなく、暴くと仰るのね"}, {"t": "narrate", "text": "声の湿りが、少しだけ本物になった。"}, {"t": "say", "name": "貂蝉", "text": "いいわ。妾も——あなたがいくらの男か、その喉首で、確かめてさしあげる"}, {"t": "sprite", "key": "diaochan_killerlove", "pos": "center"}, {"t": "narrate", "text": "笑った。今度のは、作り物じゃない。微かに、牙が見えた。"}, {"t": "narrate", "text": "上等だ。獲りに来い、刺客。わしはお前の心を獲る。お前はわしの命を獲れ。——どちらの刃が先に届くか、賭けてやろう。"}, {"t": "narrate", "text": "こうして、わしの間合いに、刃が一振り入った。"}, {"t": "narrate", "text": "——抱くか、抱かれて死ぬか。乱世で一番面白い遊びの、幕が上がった。"}, {"t": "jump", "goto": "ch1"}], "prologue_b": [{"t": "say", "name": "董卓", "text": "よく来てくれた。不自由はさせぬ。今日からここがお前の家だ。何でも申せ"}, {"t": "sprite", "key": "diaochan_fakesmile", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "……まあ。お優しいこと"}, {"t": "narrate", "text": "女は完璧に微笑んだ。完璧すぎる微笑みだった。だが、その目の奥が——乾いた。"}, {"t": "sprite", "key": "diaochan_coldeyes", "pos": "center"}, {"t": "narrate", "text": "（なんだ、この男も同じか。言葉で女を撫でて、撫でた気になる手合い。家、ですって。つまりこの男は、妾を「守ってやる弱い者」の枠に入れた。枠に入れた相手は、もう怖くない）"}, {"t": "narrate", "text": "——わしには、その心の声までは聞こえん。だが、目の奥が乾いたのは見えた。盃に注ぐ酒の、一滴の狂いもない手つき。それは愛撫ではなく、検分だった。お前は「落とせる側」だと、女は値札を貼り替えた——わしの知らぬところで。李儒だけが、静かに目を伏せた。"}, {"t": "jump", "goto": "ch1"}], "prologue_c": [{"t": "say", "name": "董卓", "text": "女など褒美の一つだ。そこで酌でもしておれ"}, {"t": "narrate", "text": "わしは女を見もしなかった。見るに値せん、と顎で示した。脅しでも、口説きでもない。ただ、棚に置いた。"}, {"t": "sprite", "key": "diaochan_fakesmile", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "……はい。仰せのままに"}, {"t": "narrate", "text": "よく出来た声だ。あまりに、よく出来ている。"}, {"t": "sprite", "key": "diaochan_coldeyes", "pos": "center"}, {"t": "narrate", "text": "女が、しおらしく頭を垂れる。だが、わしの三十年の鼻が言っている——こいつは今、安堵した。落胆ですらない。安堵だ。「物としてしか見ぬ男なら、殺すのに躊躇は要らぬ」と。わしは女の喉首を測る目を、自分から塞いでやったのだ。"}, {"t": "narrate", "text": "棚に置いた刃は、棚の上から、こちらの喉を狙い続けている。"}, {"t": "sprite", "key": "lvbu_base", "pos": "right"}, {"t": "narrate", "text": "——そして、広間の隅。戟を抱いた呂布の目が、棚に置かれた女を、ちらと舐めた。物なら、奪える。あの男はそう考える質だ。面倒の種を、わしは自分で蒔いた。"}, {"t": "jump", "goto": "ch1"}], "ch1": [{"t": "bg", "bg": "相国府・奥の私室（夜・燭の海）", "mood": "warm"}, {"t": "narrate", "text": "酒が、うまい夜だ。"}, {"t": "narrate", "text": "都の灯を全部わしの掌に握ってから、夜はいつも甘い。だが今夜の甘さは、酒のせいじゃねえ。"}, {"t": "narrate", "text": "王允とかいう爺が、献上だと言って一人の女を置いていった。忠だの社稷だのと舌を転がす爺が、わしに媚びる理由なんざ知れてる。命乞いの代わりに、女を差し出す。豚どもの作法だ。"}, {"t": "sprite", "key": "diaochan_base", "pos": "center"}, {"t": "narrate", "text": "——だが、この女は。"}, {"t": "say", "name": "貂蝉", "text": "相国さま。お酌を、よろしいでしょうか"}, {"t": "narrate", "text": "声が、奥に触る。喉でなく、もっと下を撫でてくる声だ。三十年、戦場と宴で女の声を聞いてきた。これは仕込まれた声だ。一音ずつ、男を緩ませるよう磨いてある。"}, {"t": "narrate", "text": "ほう。"}, {"t": "say", "name": "董卓", "text": "注げ"}, {"t": "sprite", "key": "diaochan_fakesmile", "pos": "center"}, {"t": "narrate", "text": "手が、来た。"}, {"t": "narrate", "text": "盃に酒を満たすその指先が、わしの指に触れる——触れる寸前で、ふと止まる。止めて、見せる。触れるか触れないかの一寸を、女は針の先みたいに研いで差し出してくる。"}, {"t": "narrate", "text": "安い女は触る。高い女ほど、触らせない。こいつは、触らせないことを商売にしてきた女だ。"}, {"t": "say", "name": "貂蝉", "text": "……熱うございますね、相国さまの手は。獣のよう"}, {"t": "say", "name": "董卓", "text": "獣で結構。お前を喰う口は、ちゃんと持ってる"}, {"t": "narrate", "text": "女が、笑った。完璧に。完璧すぎる笑みだ。目の奥だけ、燭が映ってるのに乾いている。"}, {"t": "narrate", "text": "これは仕事の顔だ。わしを値踏みしてる。どの言葉で緩み、どの酒で酔い、どの夜に隙を作るか——首から下げた帳簿に、わしを書き込んでる最中の顔だ。"}, {"t": "fx", "fx": "cutin"}, {"t": "narrate", "text": "結構。書け。書けるだけ書け。"}, {"t": "narrate", "text": "お前がわしの値を測ってる間、わしもお前の値を測ってる。お前は、わしの命を落としに来た。わしは、お前の心を落としに行く。同じ卓の上で、刃を逆向きに置いて、互いに笑ってる。"}, {"t": "narrate", "text": "——こんな面白い夜が、都にあったか。"}, {"t": "bg", "bg": "相国府・回廊（暗）", "mood": "cool"}, {"t": "sprite", "key": "liju_remonstrate", "pos": "right"}, {"t": "narrate", "text": "女が席を外した隙に、影が一つ寄ってきた。李儒だ。わしの血を流さねえ部分——毒と謀を担う、冷えた目をした男。"}, {"t": "say", "name": "李儒", "text": "太師。あの女、王允が飼っていた歌妓にございます。……刃です"}, {"t": "say", "name": "董卓", "text": "知ってる"}, {"t": "say", "name": "李儒", "text": "……知って、なお?"}, {"t": "say", "name": "董卓", "text": "爺がただで美姫を寄越すか。命乞いか、罠か。どっちにしろ、わしの間合いに刃を入れてきたってことだ。——李儒。お前ならどうする"}, {"t": "sprite", "key": "liju_insight", "pos": "right"}, {"t": "say", "name": "李儒", "text": "斬るのが定石。ですが……惜しい。あれは、ただの刃ではございませぬ。よく研がれた刃ほど、向ける先さえ握れば、味方になる。飼わず、斬らず——共犯になさいませ。ただし、ひとつ"}, {"t": "say", "name": "董卓", "text": "言え"}, {"t": "say", "name": "李儒", "text": "あの女が刃なら、必ず鞘がいる。王允の手から、女へ繋がる糸が一本はあるはず。その糸を、こちらが先に握りなされ。女の正体より——女を操る手が、いつ、どう動くかを読むのが肝要"}, {"t": "narrate", "text": "こいつの目は、女に惚れねえ。だから女の正体だけがよく見える。情の濁りがない分、構造が透けるんだ。"}, {"t": "say", "name": "董卓", "text": "面白いことを言う。お前のそういうとこは、買ってるぞ、李儒。——その糸、誰に探らせる"}, {"t": "say", "name": "李儒", "text": "私の手の者に。王允邸の裏門に、目を一つ植えてございます。三日のうちに、糸の端は掴めましょう"}, {"t": "narrate", "text": "露見、と腹の底でひとつ印を打つ。あの女が王允の刃だと、もう分かった。分かった上で——抜かせてみたくなった。"}, {"t": "narrate", "text": "わしは昔から、そういう性分だ。崖があると知って、なお縁を歩く。歩けるから歩く。落ちねえと知ってるからじゃねえ。落ちるかもしれねえ縁の上でだけ、生きてる心地がするからだ。"}, {"t": "bg", "bg": "相国府・文書庫の隅（夜・灯一つ）", "mood": "cool"}, {"t": "sprite", "key": "liju_base", "pos": "right"}, {"t": "narrate", "text": "三日の後、李儒が文書庫の隅で待っていた。女に惚れぬ、乾いた目をした男だ。情の濁りがない分、女の正体だけがよく透ける。"}, {"t": "say", "name": "李儒", "text": "あの歌妓が府に入って三日、王允の家人が二度、裏門に文を運んでおります。中身までは、まだ"}, {"t": "say", "name": "董卓", "text": "掴め。誰が、いつ、どの門を使う。それだけでいい。中身は、わしが女の口から直に聞く"}, {"t": "sprite", "key": "liju_insight", "pos": "center"}, {"t": "say", "name": "李儒", "text": "は。……出過ぎたことを申せば。あの女、刃にしては——目が、迷っております"}, {"t": "narrate", "text": "ほう。情に濁らぬ謀臣の目が、女の目の迷いを拾ったか。"}, {"t": "narrate", "text": "覚えとけ。李儒が「迷い」と言ったら、それは録だ。情じゃねえ。この男の、媚びと本気の見分けは、わしの次に利く。"}, {"t": "narrate", "text": "糸の端が、わしの手に一本、巻きついた。"}, {"t": "bg", "bg": "相国府・中庭（月）", "mood": "cool"}, {"t": "sprite", "key": "lvbu_base", "pos": "left"}, {"t": "narrate", "text": "庭を横切ると、戟を磨いてる男がいた。呂布だ。わしが手に入れた、天下無双の刃。丁原を斬ってわしの子になり、今はわしの背を守ってる。"}, {"t": "say", "name": "呂布", "text": "父上。……あの女は、何者です"}, {"t": "narrate", "text": "こいつ、女を一目見たな。声に、いつもの傲りがねえ。少し、上ずってる。"}, {"t": "sprite", "key": "lvbu_diaochan", "pos": "left"}, {"t": "narrate", "text": "虎みてえな面が、ほんの少し、童のように緩んでた。頬に、薄く血が上ってる。武に一度も疑いを持ったことのねえ男が、女一人に、初めて間合いを読み損なってる顔だ。"}, {"t": "say", "name": "董卓", "text": "献上の品だ。お前が気にすることじゃねえ"}, {"t": "say", "name": "呂布", "text": "……は。出過ぎたことを"}, {"t": "narrate", "text": "戟を磨く手が、止まらねえ。一度、二度、三度。鋼が月を返して、ぎらりと鳴く。"}, {"t": "narrate", "text": "覚えておけ。呂布が戟を磨き始めたら、それは嫉妬の狼煙だ。今はまだ、燻ってるだけ。だが——王允が連環を仕掛けたなら、こいつの嫉妬こそが、わしの喉に届く唯一の刃になる。"}, {"t": "narrate", "text": "女は、自分じゃ刺さねえ。女の役は、この戟に火を点けることだ。芯は女、火種は呂布。同じ女を真ん中に置いて、二本目の刃がわしを狙ってる。ならわしは、その芯を——先に、こっちに堕とす。"}, {"t": "bg", "bg": "相国府・奥の私室（夜・燭の海）", "mood": "warm"}, {"t": "sprite", "key": "diaochan_base", "pos": "center"}, {"t": "narrate", "text": "女が、戻ってきた。"}, {"t": "narrate", "text": "さっきより、一歩近い。間合いを詰めてきやがった。仕事熱心なことだ。今夜のうちに隙を作って、わしを骨抜きにする算段だろう。"}, {"t": "sprite", "key": "diaochan_killerlove", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "お一人で、お寂しゅうございましょう。……妾でよろしければ、今宵は、お側に"}, {"t": "narrate", "text": "帯に、自分で手をかけた。ほどく——その手前で、止める。"}, {"t": "narrate", "text": "薄衣の肩が、すべり落ちる音だけ、聞こえた。画は見せねえ。見せねえことが、こいつの刃だ。あと一寸、あと一寸と、見せないものを餌にして、男の喉を掻き切る間合いまで引き込む。"}, {"t": "fx", "fx": "letterbox"}, {"t": "narrate", "text": "来た。ここが、女の罠の口だ。"}, {"t": "narrate", "text": "そして——ここが、わしの口説きの口でもある。"}, {"t": "sprite", "key": "dongzhuo_lust", "pos": "center"}, {"t": "narrate", "text": "わしはこの女を、どう堕とす。"}, {"t": "choice", "options": [{"text": "嘘を嘘と承知の上で、「お前が欲しい」と正面から告げる", "d": {"diaochan": 2, "roken": -1}, "goto": "ch1_a"}, {"text": "玉と錦を積み、甘い言葉で機嫌を取って気を引く", "d": {"diaochan": -2, "roken": 1}, "goto": "ch1_b"}, {"text": "腕をつかんで組み伏せ、わが物だと刻みつける", "d": {"diaochan": -1, "rogan": 1}, "goto": "ch1_c"}]}], "ch1_a": [{"t": "narrate", "text": "わしは、女の手首をつかんだ。帯をほどく手を、止めさせた。"}, {"t": "say", "name": "董卓", "text": "やめろ。脱ぐな。——その手管、わしには要らん"}, {"t": "sprite", "key": "diaochan_fakesmile", "pos": "center"}, {"t": "say", "name": "董卓", "text": "お前が刃なのは、分かってる。王允の飼い犬だってこともな。隙を作って、わしを緩めて、いつか呂布の戟をわしに向けさせに来る。——それも分かってて、言う。わしは、お前が欲しい。芝居のお前じゃねえ。刃のお前ごと、欲しい"}, {"t": "fx", "fx": "flash"}, {"t": "say", "name": "董卓", "text": "刺客を差し向けるなら、抱かれながら差し向けてみろ。それで死ぬなら、わしはその程度の男だったってだけだ"}, {"t": "sprite", "key": "diaochan_flustered", "pos": "center"}, {"t": "narrate", "text": "女の目から——燭の映りが消えた。"}, {"t": "narrate", "text": "笑みは、まだ顔に貼りついてる。だが目だけが、追いつかなかった。台本にねえ言葉を浴びて、次の頁が、白くなってる顔だ。"}, {"t": "narrate", "text": "わしは、こいつが嘘をついた瞬間を、いくつも見てきた。だが今、こいつは——嘘をつけずにいる。"}, {"t": "say", "name": "貂蝉", "text": "……っ、なんて、ことを。妾の仕事を……奪う気ですか。あなたは"}, {"t": "narrate", "text": "一人称が、揺れた。「妾」の作法の奥から、素の女が、半歩だけ顔を出した。"}, {"t": "narrate", "text": "——これだ。この一瞬。獲ったぞ。まだ点を入れただけだ。だが確かに、女の演技にひびが入った音がした。"}, {"t": "narrate", "text": "〔貂蝉好感度＋2／露見−1〕——女が任務を進めにくくなる。媚びでも支配でもねえ。真横から、獣が獣として、刃ごと欲しがる。それだけが、こいつの演技を剥がす。"}, {"t": "jump", "goto": "ch2"}], "ch1_b": [{"t": "say", "name": "董卓", "text": "待て。脱ぐ前に——これを見ろ。西域の玉だ。錦も、好きなだけ持って行け。お前ほどの女には、これくらいの礼を尽くさんとな"}, {"t": "sprite", "key": "diaochan_fakesmile", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "……まあ。お上手なこと"}, {"t": "narrate", "text": "女が、完璧に微笑んだ。"}, {"t": "sprite", "key": "diaochan_coldeyes", "pos": "center"}, {"t": "narrate", "text": "何かが、冷えた。"}, {"t": "narrate", "text": "女の目が、玉でも錦でもなく、わしを見てる。見て——格を、貼り替えた目だ。"}, {"t": "say", "name": "貂蝉", "text": "（……なんだ、この男も。言葉で女を撫でて、撫でた気になる手合い。玉で女が買えると思ってる。漢朝のお偉方と、同じ顔。——退屈。これなら、わざわざ妾が動くまでもない。呂布に焚きつければ、ひと月で済む）"}, {"t": "sprite", "key": "diaochan_killerlove", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "嬉しゅうございます。……相国さまは、お優しいのですね"}, {"t": "narrate", "text": "優しい、と言われた。背筋が、ぞっとした。"}, {"t": "narrate", "text": "こいつの口で「優しい」は、褒め言葉じゃねえ。「御しやすい」と同じ意味だ。わしは今、こいつの帳簿で——「呂布をけしかけりゃ済む側」に書き換えられた。"}, {"t": "narrate", "text": "〔貂蝉好感度−2／露見＋1〕——媚びは、女の刃を一寸、前に進めただけだった。媚びる男は、男を喰らう女には獲物にすらならねえ。手間をかける価値もねえ「処理対象」だ。"}, {"t": "jump", "goto": "ch2"}], "ch1_c": [{"t": "say", "name": "董卓", "text": "御託はいい。お前はもう、わしの物だ"}, {"t": "narrate", "text": "女の腕をつかんで、引き寄せた。力で。わが物だと、肉に刻むように。"}, {"t": "sprite", "key": "diaochan_killerlove", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "……ええ。あなたの、物。お好きになさって"}, {"t": "narrate", "text": "女は、抗わなかった。微笑んだまま、身を預けてきた。だが——披帛の下で、指が、何かの柄に触れた気がした。柄に触れて——そっと、離した。自分じゃ抜かねえ。抜かせる相手は、別にいる女の手つきだ。"}, {"t": "narrate", "text": "こいつは、物にされた女の顔をしてる。物にされた女は、もう、男を怖がらねえ。怖がらねえ女は——いつでも、別の刃を、わしに向けられる。"}, {"t": "narrate", "text": "わしは、女の心じゃなく、女の体だけを握った。心は、するりと、手の外へ逃げた。"}, {"t": "bg", "bg": "相国府・回廊（呂布が見ている）", "mood": "cool"}, {"t": "sprite", "key": "lvbu_cold", "pos": "left"}, {"t": "narrate", "text": "回廊の奥で、戟を磨く音が——止まった。"}, {"t": "sprite", "key": "lvbu_diaochan", "pos": "center"}, {"t": "narrate", "text": "呂布が、見てる。わしが女を物のように扱う、その様を。あいつの目に、別の火が点いた。物にされる女が、惜しい。そういう火だ。"}, {"t": "narrate", "text": "女は、まだ何もしてねえ。指一本、わしに向けちゃいねえ。なのに、刃の方が——勝手に、熱を持ち始めた。これが連環だ。"}, {"t": "narrate", "text": "〔貂蝉好感度−1／呂布嫉妬＋1〕——体は獲った。心は逃げ、もう一本の刃が、熱を持った。"}, {"t": "jump", "goto": "ch2"}], "ch2": [{"t": "bg", "bg": "郿塢・董卓私邸 奥院／夜明け前の薄闇", "mood": "cool"}, {"t": "narrate", "text": "月が、ひと巡りした。"}, {"t": "narrate", "text": "表では兵が要を守り、洛陽では公卿どもが息を殺している。だが、わしはこのひと月、奥院から出ておらん。"}, {"t": "narrate", "text": "政務?　李儒が積み上げた竹簡は、卓の上で埃をかぶっておるわ。"}, {"t": "sprite", "key": "diaochan_fakesmile", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "太師さま。……また、お目覚めが早うございますね"}, {"t": "say", "name": "貂蝉", "text": "妾の寝顔を、そう飽きずに見ていられるものですか"}, {"t": "narrate", "text": "薄絹一枚を肩に引っかけただけの女が、香炉の煙の向こうで笑う。"}, {"t": "narrate", "text": "黒髪が褥に溢れ、白い喉が灯に濡れている。十六の小娘が、なぜこうも男を絡め取る術を知っておる。"}, {"t": "narrate", "text": "……知っておる、というそのことが、答えだ。"}, {"t": "narrate", "text": "わしはこの女を、罠と知って納れた。王允の置いた刃だと、最初から分かっておる。"}, {"t": "narrate", "text": "なのに、このひと月、わしはこの刃で自分の喉を撫でさせて遊んでおる獣だ。"}, {"t": "narrate", "text": "──このしなだれは、本物か。"}, {"t": "narrate", "text": "それとも、わしがいつ眠るか、いつ油断するかを測る、芝居の指先か。"}, {"t": "sprite", "key": "diaochan_flustered", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "……怖いお顔。妾、なにか粗相を?"}, {"t": "narrate", "text": "怖い顔だと?　笑止な。お前のその憂い顔こそ、いつ刃に変わるか分からぬ造り物よ。"}, {"t": "narrate", "text": "だが──分からぬからこそ、面白い。本物の惚れなら獲ってやる。芝居なら、芝居ごと暴いて惚れさせてやる。どちらにせよ、逃がさん。"}, {"t": "sprite", "key": "dongzhuo_lust", "pos": "center"}, {"t": "say", "name": "董卓", "text": "飽きるものか。お前は罠だ。罠ほど飽きぬ玩具はないわ"}, {"t": "narrate", "text": "女が、ほんの一瞬、目を細めた。"}, {"t": "narrate", "text": "──今のは、媚びへの安堵か。それとも、見抜かれた者の凍りつきか。"}, {"t": "narrate", "text": "見極めきれぬまま、その喉に噛みつくように口づける。女は逆らわぬ。逆らわぬことが、また分からぬ。"}, {"t": "fx", "fx": "blackout"}, {"t": "bg", "bg": "奥院・回廊／朝", "mood": "warm"}, {"t": "sprite", "key": "liju_remonstrate", "pos": "center"}, {"t": "say", "name": "李儒", "text": "太師。……お顔の色が、よろしくない"}, {"t": "say", "name": "李儒", "text": "ひと月、政の卓に座られぬのは、太師らしくありませぬ。火は、燃やす先を持ってこそ火。香炉の中で燻る火は、ただの灰になりまする"}, {"t": "narrate", "text": "灰、と言いおったか。この李儒、舌だけは切れる。"}, {"t": "sprite", "key": "dongzhuo_base", "pos": "center"}, {"t": "say", "name": "董卓", "text": "言うてみよ。何が気に食わん"}, {"t": "sprite", "key": "liju_insight", "pos": "center"}, {"t": "say", "name": "李儒", "text": "あの歌伎にございます"}, {"t": "say", "name": "李儒", "text": "太師。妾を寵されるのは結構。なれど──あの女、父子の間に立っておりまする"}, {"t": "narrate", "text": "父子、とは。わしと、奉先のことだ。"}, {"t": "say", "name": "李儒", "text": "温侯呂布。あの猛き者が、近頃あなたを見る目が、剣呑にございます。些細なことで温侯を責められますな。──温侯を責めるたび、あの女が、その裂け目に指を差し込んでおる気が、それがしにはいたします"}, {"t": "say", "name": "李儒", "text": "あの女が、父子を裂いておりまする。お気をつけなされ"}, {"t": "narrate", "text": "李儒の言、容れるか。聞き流すか。"}, {"t": "choice", "options": [{"text": "「李儒、王允と奉先を繋ぐ糸を、お前の手の者に手繰らせよ」と命じる", "d": {"liju": 1, "roken": 1}, "goto": "ch2_main2"}, {"text": "「女ひとりで父子が裂けるか。買いかぶりよ」と笑い飛ばす", "d": {"liju": -1}, "goto": "ch2_main2"}]}], "ch2_main2": [{"t": "narrate", "text": "──手繰らせよ、と言いかけて、わしは舌を止めた。"}, {"t": "narrate", "text": "いや。手繰らせる。罠の糸の在処を知っておいて損はない。獲物を仕留めるにも、罠を踏み抜くにも、地図はいる。"}, {"t": "sprite", "key": "dongzhuo_base", "pos": "center"}, {"t": "say", "name": "董卓", "text": "李儒。お前の手の者に、王允邸と奉先の間を洗わせよ。誰が、誰に、何を約束したか。糸の端まで残らずだ"}, {"t": "sprite", "key": "liju_base", "pos": "center"}, {"t": "say", "name": "李儒", "text": "……御意。賢明にございます"}, {"t": "narrate", "text": "李儒の目が、わずかに緩んだ。こやつが安堵を見せるなど、滅多にない。"}, {"t": "narrate", "text": "だが、わしが網を打たせたのは、お前の言を容れたからではないぞ、李儒。"}, {"t": "narrate", "text": "あの女の正体を、わし自身が、わしの手で暴きたいだけだ。"}, {"t": "bg", "bg": "鳳儀亭／荷花池に映る月／夕暮れから宵へ", "mood": "cool"}, {"t": "narrate", "text": "その日、わしは公卿との宴を中座した。胸騒ぎがした。獣の勘だ。"}, {"t": "narrate", "text": "奥院に女がおらぬ。侍女に問えば、鳳儀亭へ涼みに、と。"}, {"t": "narrate", "text": "──鳳儀亭。奉先が、近頃よく足を向ける場所。"}, {"t": "narrate", "text": "回廊を渡り、亭の柱の影に立ったわしは、そこで足を止めた。"}, {"t": "narrate", "text": "見るな、という勘と、見ろ、という勘が、同時に首筋を撫でた。"}, {"t": "sprite", "key": "diaochan_tears", "pos": "left"}, {"t": "sprite", "key": "lvbu_diaochan", "pos": "right"}, {"t": "say", "name": "貂蝉", "text": "温侯さま……妾はもう、生きてはおられませぬ"}, {"t": "say", "name": "貂蝉", "text": "太師に──汚されたこの身。あなたさまの妻になると誓うた、この身が。妾、いっそこの池に身を沈めて、志を明かしとうございます"}, {"t": "sprite", "key": "diaochan_suicide", "pos": "center"}, {"t": "narrate", "text": "女が、荷花池へ身を投げようとする。白い腕が水面へ伸びる。"}, {"t": "narrate", "text": "呂布が、慌ててそれを抱き止めた。あの戟の鬼が、童のように狼狽えておる。"}, {"t": "say", "name": "貂蝉", "text": "殿が……殿がそれほどまでに、あの老賊を恐れておられるなら"}, {"t": "say", "name": "貂蝉", "text": "妾には、もう二度と、天の日を仰ぐ日は参りませぬ……!"}, {"t": "narrate", "text": "臆病を、煽っておる。"}, {"t": "narrate", "text": "──煽っておる、と、わしには見える。この女の涙が天性の武器だと、わしは褥で嫌というほど浴びてきたからだ。"}, {"t": "narrate", "text": "だが奉先には見えぬ。あの単純な戟の鬼には、目の前の女の涙が、ただ本物に見えておる。"}, {"t": "sprite", "key": "diaochan_fakesmile", "pos": "center"}, {"t": "narrate", "text": "そして、わしは、見た。"}, {"t": "narrate", "text": "女が、呂布の背中越しに、己の胸を指した。次に、奥──わしの居室の方角を指した。そして香羅で、つ、と涙を拭った。"}, {"t": "narrate", "text": "「妾の心はあなた。なれど、あの男に囚われている」──そう告げる、無言の合図だ。"}, {"t": "narrate", "text": "芝居だ。"}, {"t": "narrate", "text": "これは、芝居だ。わしへの涙も、奉先への涙も、ぜんぶ同じ女の、同じ指先から出ておる。"}, {"t": "fx", "fx": "flash"}, {"t": "narrate", "text": "なのに。"}, {"t": "narrate", "text": "なのに、なぜわしの腹の底が、こうも焼ける。"}, {"t": "narrate", "text": "あの指が、わしではなく奉先の背に触れている。あの涙が、わし以外の男のために流れている。"}, {"t": "narrate", "text": "──たとえそれが芝居でも。芝居でも、わしは、許せん。"}, {"t": "narrate", "text": "俺の女だ。"}, {"t": "narrate", "text": "……。"}, {"t": "narrate", "text": "わし、ではない。俺、と。今、心の底で、そう言いかけた。"}, {"t": "narrate", "text": "乱れている。この女に、芯まで掴まれかけている。獣の王たるわしが、十六の歌伎の指先ひとつで、己の一人称すら取り落としかけておる。"}, {"t": "narrate", "text": "笑え。笑える話だ。──笑えぬ。"}, {"t": "fx", "fx": "cutin"}, {"t": "sprite", "key": "dongzhuo_fury", "pos": "center"}, {"t": "say", "name": "董卓", "text": "奉先ッ──!!"}, {"t": "sprite", "key": "lvbu_betrayed", "pos": "center"}, {"t": "narrate", "text": "わしは奉先の画戟を奪い、その背へ投げつけた。"}, {"t": "narrate", "text": "鋼が宙を裂き、亭の柱を割って突き立つ。奉先は跳ねるように身を翻し、戟をかわして逃げた。あの鬼の足の速さよ。──惜しい。当てる気で投げたわ。"}, {"t": "narrate", "text": "追おうとしたわしの前に、息を切らせた李儒が立ち塞がった。"}, {"t": "sprite", "key": "liju_remonstrate", "pos": "center"}, {"t": "say", "name": "李儒", "text": "太師ッ、なりませぬ! お鎮まりを!"}, {"t": "say", "name": "李儒", "text": "温侯を、女ひとりのために斬られますか! 天下に並ぶ者なき爪牙を、たかが歌伎一人と引き換えに、失われると申されるか!"}, {"t": "narrate", "text": "たかが、だと。"}, {"t": "narrate", "text": "そのたかが歌伎に、わしは今、己の名すら取り落とした。"}, {"t": "say", "name": "李儒", "text": "太師。……それがし、申し上げました。あの女が、父子を裂くと"}, {"t": "say", "name": "李儒", "text": "このままでは──われら皆、女の手にかかって死にまするぞ"}, {"t": "narrate", "text": "女の手にかかって死ぬ、と李儒は言う。"}, {"t": "narrate", "text": "ばかな。死ぬのはわしではない。殺すと言って殺し、奪うと言って奪うのがわしだ。火が、薪に焼かれて死ぬか。"}, {"t": "narrate", "text": "──だが、その火が、たった今、十六の小娘の涙ひとつで揺らいだのを、わしは己で見た。"}, {"t": "narrate", "text": "振り向けば、池のほとりに女が立っている。"}, {"t": "sprite", "key": "diaochan_killerlove", "pos": "center"}, {"t": "narrate", "text": "濡れた頬。乱れた裾。けれどその目の奥に、ひと欠片──涙では拭えぬ、冷たい光が灯っておる。"}, {"t": "narrate", "text": "あれは、惚れた女の目か。わしの喉を測り続ける、刺客の目か。"}, {"t": "narrate", "text": "……分からぬ。ひと月褥を共にして、なお分からぬ。"}, {"t": "narrate", "text": "信じたい、と思う己がいる。同時に、信じた瞬間にこの喉を裂かれる絵が見える。"}, {"t": "narrate", "text": "女が、こちらへ歩いてくる。火に焼かれぬ顔で、わしという火の中へ。"}, {"t": "narrate", "text": "さあ──この女を、どう捌く。"}, {"t": "choice", "options": [{"text": "「お前の涙が芝居か本物か、わしが暴く」と貂蝉の顎を取り見据える", "d": {"diaochan": 2, "roken": 1}, "goto": "ch2_a"}, {"text": "嫉妬を呑み「呂布のことは気にせぬ」と物分かりよく振る舞う", "d": {"diaochan": -1}, "goto": "ch2_b"}, {"text": "呂布を呼びつけ力で主従の上下を刻む", "d": {"rogan": 2, "diaochan": -1}, "goto": "ch3"}, {"text": "李儒に王允と呂布の糸を手繰らせる", "d": {"liju": 1, "roken": 1}, "goto": "ch3"}]}], "ch2_a": [{"t": "narrate", "text": "わしは女の歩みを待たず、踏み込んだ。逃がさん。"}, {"t": "narrate", "text": "顎を、指で掬い上げる。無理やり、わしの目とその目を、まっすぐ重ねる。"}, {"t": "sprite", "key": "dongzhuo_menace", "pos": "center"}, {"t": "say", "name": "董卓", "text": "貂蝉。今のは、見せておった芝居か"}, {"t": "say", "name": "董卓", "text": "奉先への涙が芝居なら──わしへの涙も、ぜんぶ芝居だな"}, {"t": "sprite", "key": "diaochan_flustered", "pos": "center"}, {"t": "narrate", "text": "女の睫毛が、震えた。──この震えすら、芝居かもしれぬ。だが構わぬ。"}, {"t": "say", "name": "董卓", "text": "だが、わしはお前の芝居を恐れぬ。お前が刃なら、刃のまま抱く。お前がわしの喉を狙うなら、狙わせたまま、その心を獲る"}, {"t": "say", "name": "董卓", "text": "逃げるな、貂蝉。お前はわしの好敵手だ。媚びる女なら、とうに飽きて捨てておるわ。──お前は、捨てさせぬ気だろう"}, {"t": "narrate", "text": "女の目から、すうっと造り物の憂いが剥がれた。代わりに現れたのは、笑みだ。"}, {"t": "sprite", "key": "diaochan_killerlove", "pos": "center"}, {"t": "narrate", "text": "今までの、甘く媚びる笑みではない。牙を剥くような、対等の笑みだ。"}, {"t": "sprite", "key": "diaochan_killerlove", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "……ふ。やはり、あなたは媚びを喜ばぬお方"}, {"t": "say", "name": "貂蝉", "text": "妾の涙に蕩けて骨抜きになる男なら、もうとうに、殺しておりました"}, {"t": "narrate", "text": "殺しておりました、と、色を含んだ声で、こうもあっさり言う。"}, {"t": "narrate", "text": "──これだ。この女が刃を見せる時だけ、わしは確かに、こいつに惚れておると思える。惚れさせられておるのか、惚れさせておるのか、もはや境目が溶けておる。"}, {"t": "say", "name": "董卓", "text": "言うな。──暴いてやる。お前のその刃の根が、憎しみか、惚れか。お前自身が知らんものを、わしが先に暴く"}, {"t": "say", "name": "貂蝉", "text": "……どうぞ。暴けるものなら"}, {"t": "narrate", "text": "顎を掴んだまま、その唇を奪う。女は応える。応えながら、その指先がわしの帯に──刃のように、滑る。"}, {"t": "narrate", "text": "抱くのか、刺すのか。今宵も分からぬまま、わしはこの刃を、褥へ引き込んだ。"}, {"t": "fx", "fx": "blackout"}, {"t": "narrate", "text": "露見は、進んだ。李儒の網が、王允と奉先を結ぶ糸を、一筋たぐり寄せてくる。"}, {"t": "narrate", "text": "──連環。糸の名は、まだ知らぬ。だが、輪が、見えかけている。"}, {"t": "jump", "goto": "ch3"}], "ch2_b": [{"t": "sprite", "key": "dongzhuo_tender", "pos": "center"}, {"t": "say", "name": "董卓", "text": "……奉先のことは、気にせぬ。お前が泣くな。わしが悪かった"}, {"t": "sprite", "key": "diaochan_coldeyes", "pos": "center"}, {"t": "narrate", "text": "言った瞬間、女の頬の涙が、すっと乾いた気がした。"}, {"t": "narrate", "text": "物分かりよく、嫉妬を呑んでみせた。広い男を演じてみせた。それが悪手だと、女の冷えた目が教えてくる。"}, {"t": "say", "name": "貂蝉", "text": "まあ。お優しいこと"}, {"t": "say", "name": "貂蝉", "text": "……太師さまは、妾に嫌われたくないのですね"}, {"t": "narrate", "text": "違う、と言いかけて、言えぬ。図星だからではない。この女の前で、嫉妬を隠して善人ぶった己が、急に薄っぺらく感じられたからだ。"}, {"t": "narrate", "text": "媚びたのだ。獣の王が、十六の小娘の機嫌を取りに、牙を引っ込めて。"}, {"t": "narrate", "text": "女が求めておったのは、わしの寛容ではない。わしの、嘘のない獣だ。それを引っ込めた瞬間、こいつはわしを\"獲物\"の側に分類した。冷めた目が、そう言うておる。"}, {"t": "sprite", "key": "diaochan_killerlove", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "ええ、ええ。気にしませぬとも。──太師さまが、そう仰るなら"}, {"t": "narrate", "text": "しなだれてくる。だが、その温度が、一段低い。"}, {"t": "narrate", "text": "しまった、と思う。が、もう遅い。この一手で、わしはこの刃を、ほんの少し遠ざけた。"}, {"t": "jump", "goto": "ch3"}], "ch3": [{"t": "bg", "bg": "郿塢_太師私室_夜", "mood": "night"}, {"t": "narrate", "text": "燭(ともしび)が一つ、揺れている。"}, {"t": "narrate", "text": "郿塢(びう)の奥、わしだけの部屋だ。壁には宝剣、卓には酒。外には三十万斛(こく)の穀(こく)を積み、城壁は長安と同じ厚さに築かせた。ここまで来た。羌(きょう)の砂を喰って生き延びた男が、天子を膝下に置くところまで来た。"}, {"t": "narrate", "text": "なのに、いま、わしの背に汗を浮かせているのは、十六の小娘ひとりだ。"}, {"t": "sprite", "key": "diaochan_base", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "太師さま。お酌を"}, {"t": "narrate", "text": "白い手が壺を傾ける。酒が満ちる。指の先まで、計算され尽くした美しさだ。"}, {"t": "narrate", "text": "──信じたいか? わしを慕う仕草に見える。だがこの女が、王允の手から差し出された刃だということを、わしは一日も忘れたことがない。早すぎる甘さは疑え。蜜ほど、毒を隠すには都合がいい。"}, {"t": "fx", "fx": "fade"}, {"t": "narrate", "text": "李儒(りじゅ)だ。あの男の足音は、扉を叩く前から分かる。乱れがない。"}, {"t": "sprite", "key": "liju_remonstrate", "pos": "left"}, {"t": "say", "name": "李儒", "text": "太師。人払いを願います。──御身の、命に関わる話です"}, {"t": "narrate", "text": "貂蝉が裾を引いて退がる。去り際、ほんの一瞬、その目が李儒を斬った。殺意ではない。値踏みだ。「この男は邪魔だ」と、確かにそう測った。"}, {"t": "narrate", "text": "わしは見逃さなかった。だが李儒も、見逃してはいなかった。"}, {"t": "say", "name": "李儒", "text": "太師。昔、楚の荘王(そうおう)の宴で、灯が消えた隙に、王の妃の衣を引いた者がおりました。妃は男の冠の纓(ひも)を引きちぎり、灯を点せばその者を罰せよと王に告げた"}, {"t": "say", "name": "李儒", "text": "されど荘王は──全員に纓を切らせ、灯を点した。誰が無礼を働いたか、永遠に分からぬようにした。後の戦で、王の窮地に死力を尽くして救った将がおりました。あの夜、纓を切られた男です"}, {"t": "narrate", "text": "知っている。臣の恥を呑んだ王が、命で報いられた話だ。"}, {"t": "narrate", "text": "そして、この男が何を言いに来たかも、もう分かっている。"}, {"t": "say", "name": "李儒", "text": "貂蝉を、呂布(りょふ)に賜りなさい"}, {"t": "narrate", "text": "燭が爆ぜた。"}, {"t": "say", "name": "李儒", "text": "奉先(ほうせん)は猛将です。あれの戟(げき)があればこそ、太師の御身は安泰。なれど──太師はあの女を奪った。呂布は知っております。じわじわと、毒のように。あの男の忠が、いま女ひとりで腐りかけている"}, {"t": "say", "name": "李儒", "text": "女を下げ渡せば、呂布は大恩に感じ、死力で報いましょう。荘王の纓と同じ。失うのは妓女(ぎじょ)ひとり。得るのは天下無双の戟です。釣り合いませぬ。──否、釣り合わぬからこそ、賜るのです"}, {"t": "narrate", "text": "一理ある。冷たく、正しい勘定(かんじょう)だ。わしの中の武人が、確かに頷いた。"}, {"t": "narrate", "text": "──だが。"}, {"t": "narrate", "text": "賜る? あれを? 呂布の腕の中に、あの白い喉を?"}, {"t": "narrate", "text": "胸の奥で、聞いたことのない音が鳴った。獣が、唸った。"}, {"t": "say", "name": "李儒", "text": "もう一度、申します。女に惑わされてはなりませぬ"}, {"t": "say", "name": "李儒", "text": "太師。あの女は、まこと、ただの献上品でしょうか。王允(おういん)が──あの面従腹背の老狐が、虎の口に手ずから生肉を入れる。なぜ。骨が仕込んであるからではないと、誰が言えます"}, {"t": "narrate", "text": "こいつは、見えている。"}, {"t": "narrate", "text": "並みの謀臣なら「美姫を得て祝着」と世辞を言う。だがこの男だけが、献上された蜜の底を覗き、毒を嗅ぎ当てている。──連環(れんかん)の鎖の、輪郭を。"}, {"t": "sprite", "key": "liju_insight", "pos": "left"}, {"t": "say", "name": "李儒", "text": "われら皆、女の手にかかって死にますぞ。──この李儒、太師の屍(かばね)に連座して、市曹(しそう)で斬られる夢を、三たび見ました"}, {"t": "narrate", "text": "三たび、と言ったな。"}, {"t": "narrate", "text": "この乾いた男が、夢の話などするのは初めてだ。"}, {"t": "fx", "fx": "blackout"}, {"t": "narrate", "text": "李儒を退がらせ、貂蝉を呼んだ。"}, {"t": "narrate", "text": "試してやる。この女が刃なら、刃を抜かせてやる。安全な距離など、わしの流儀ではない。"}, {"t": "sprite", "key": "diaochan_fakesmile", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "お呼びと伺いました。……李儒さまは、何を?"}, {"t": "narrate", "text": "おまえの心配は、わしの命か。それとも、わしの命を狙う段取りが狂うことか。"}, {"t": "say", "name": "董卓", "text": "貂蝉。──おまえを、呂布に賜ろうと思う"}, {"t": "narrate", "text": "言った瞬間、わしは女の全身を見ていた。瞳孔、喉、指の関節、裾の重心。羌(きょう)の草原で、矢を放つ寸前の獣を見るときと、同じ目で。"}, {"t": "fx", "fx": "cutin"}, {"t": "sprite", "key": "diaochan_coldeyes", "pos": "center"}, {"t": "narrate", "text": "笑みが、剥がれた。"}, {"t": "narrate", "text": "化粧の下、ほんの○・一拍。素の顔が出た。──それは怯えでも、女の媚びでもなかった。獲物を逃すまいとする、狩人の顔だった。"}, {"t": "narrate", "text": "ああ、やはり。"}, {"t": "narrate", "text": "そして次の刹那。"}, {"t": "fx", "fx": "flash"}, {"t": "sprite", "key": "diaochan_suicide", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "──いっそ、殺してくださいませ!!"}, {"t": "narrate", "text": "壁の宝剣だ。わしの剣を、わしの女が抜いた。切先は、わし──ではない。己の白い喉に当てている。"}, {"t": "say", "name": "貂蝉", "text": "賜る? 呂布に? ……ならば妾(わらわ)は、ここで死にます。太師の御前で。志を、お見せして"}, {"t": "narrate", "text": "刃は、わしへ来ない。"}, {"t": "narrate", "text": "来ないことが、何より雄弁だった。"}, {"t": "narrate", "text": "わしは知っている。原文を、構図を、骨を。"}, {"t": "narrate", "text": "──この女は、決してわしを斬らぬ。喉を裂くなら己の喉。止めを刺すのは、いつも別の手だ。自分の血で、男を縛りにかかる女。"}, {"t": "narrate", "text": "連環の、鎖が見えた。"}, {"t": "narrate", "text": "王允(おういん)が、まず呂布に「この娘を娶らせる」と約した。次にわしに献じた。呂布は奪われたと思い込む。女は呂布の前で泣き、わしの前でも泣く。両の男の胸に、同じ毒を回す。やがて若い戟が、嫉妬に灼かれて主に向く──"}, {"t": "narrate", "text": "これは、わしを討つための、鎖だ。一片の隙もない。"}, {"t": "narrate", "text": "確信した。この女は、わしを殺す刃だ。間違いなく。"}, {"t": "narrate", "text": "──なのに。"}, {"t": "narrate", "text": "切先の下で、白い喉が、上下している。速い。速すぎる。あれは芝居の息か。それとも、本当に死を覚悟した者の息か。"}, {"t": "narrate", "text": "任務で喉に刃を当てる女が、こうも震えるか。"}, {"t": "narrate", "text": "それとも、この震えすら、わしに「本物だ」と信じさせるための、最後の演技か。"}, {"t": "narrate", "text": "分からぬ。"}, {"t": "narrate", "text": "──分からぬのが、たまらなく、面白い。"}, {"t": "say", "name": "董卓", "text": "下ろせ"}, {"t": "narrate", "text": "わしは女の手首を掴み、剣をもぎ取り、その細い身を腕に抱き込んだ。羌の弓を引く腕だ。逃げられはせぬ。"}, {"t": "sprite", "key": "diaochan_tears", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "……これは、李儒の、計でございます。あの男が、妾(わらわ)を太師から離そうと。……妾は、妾はあの呂布の、肉を……生きながら、噛みちぎってやりたい……!"}, {"t": "narrate", "text": "噛みちぎりたい、と言った。"}, {"t": "narrate", "text": "美姫の口から出る言葉ではない。だが、その声の底に、ひと匙(さじ)の本物が混じっていた気がした。──気がした、だけかもしれぬ。"}, {"t": "narrate", "text": "腕の中で、女が泣いている。涙が熱い。体温がある。芝居の涙に、これほどの熱が出せるものか。"}, {"t": "narrate", "text": "出せる、とわしの中の武人が言う。"}, {"t": "narrate", "text": "出せぬ、とわしの中の、名前のない何かが言う。"}, {"t": "sprite", "key": "diaochan_killerlove", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "……(おかしい。この涙は、計のはず。喉に刃を当てたのも、段取り通り。なのに──なぜ、この太く熱い腕に抱かれて、ほっとしている。なぜ、見抜かれたのに、安堵している)"}, {"t": "say", "name": "貂蝉", "text": "(王允さま。妾は……妾は、いま、誰を騙しているのです。この男を。──それとも、自分を)"}, {"t": "narrate", "text": "女の睫毛(まつげ)が濡れて、震えている。"}, {"t": "narrate", "text": "こいつも、分かっていないのだ。どこまでが任務で、どこからが本心か。境目が、溶けかけている。狩る側が、獲物の体温に絆(ほだ)されかけている。"}, {"t": "narrate", "text": "──ならば、勝負だ。この溶けかけた境目を、わしの火で、どちらに転ばせる。"}, {"t": "fx", "fx": "blackout"}, {"t": "narrate", "text": "女を寝所に残し、廊下へ出ると、李儒が柱の影に立っていた。退がっていなかった。"}, {"t": "narrate", "text": "この男が命じられた通りに退がったことなど、一度もない。だから生きている。"}, {"t": "sprite", "key": "liju_scheming", "pos": "right"}, {"t": "say", "name": "李儒", "text": "太師。お聞きあそばしましたか。あの女の口から『連環』の二字が、ほぼ零(こぼ)れた。──ならば、こう返せます"}, {"t": "say", "name": "李儒", "text": "王允の鎖は、呂布の嫉妬を太師に向ける仕掛け。なれば、その鎖を、逆しまに使う。呂布の刃を、太師ではなく──王允へ。向け替えるのです"}, {"t": "narrate", "text": "逆用。連環を、連環で討つ。"}, {"t": "say", "name": "李儒", "text": "呂布が『誰に騙された』と気づく日を、こちらが先に設計する。女が泣くたび、太師は呂布に囁いておくのです。『おまえに貂蝉を約したのは誰だ。先に奪うと言って、後で寄越さなかったのは、誰だ』と。──恨みの矢じりを、王允の喉へ研いでおく"}, {"t": "sprite", "key": "liju_remonstrate", "pos": "center"}, {"t": "say", "name": "李儒", "text": "ただし。──太師があの女に溺れ、李儒の言を蹴る日が一日でも来れば、この活路は閉じます。鎖は元の向きに戻り、戟は太師の咽喉(のど)へ来る。北の掖門(えきもん)で。……それも、夢に見ました"}, {"t": "narrate", "text": "北の掖門。"}, {"t": "narrate", "text": "また、この男は見ている。わしの見えぬ岸を。"}, {"t": "narrate", "text": "腕の中の体温。喉に当てられていた刃。涙。殺意。「噛みちぎりたい」と言った声。"}, {"t": "narrate", "text": "刺客と、知った。連環と、見抜いた。それでもなお──わしは、この女を、どうする。"}, {"t": "choice", "options": [{"text": "「お前が刃なら、その刃ごと俺のものだ」と本気で落としにいく", "d": {"diaochan": 3, "roken": 1}, "goto": "ch3_a"}, {"text": "「もう刺客の真似はよせ、許してやる」と優しく赦す", "d": {"diaochan": -2}, "goto": "ch3_b"}, {"text": "李儒の諫言を容れ、罠の鎖を断つ策を巡らす", "d": {"liju": 2, "roken": 2}, "goto": "ch3_c"}, {"text": "裏切りを恐れ鎖で縛りつける", "d": {"diaochan": -2, "rogan": 1}, "goto": "ch3_d"}]}], "ch3_a": [{"t": "fx", "fx": "cutin"}, {"t": "narrate", "text": "わしは女の顎を掬い、上向かせた。涙の膜の奥で、瞳が揺れている。"}, {"t": "say", "name": "董卓", "text": "貂蝉。聞け。おまえが王允の刃だろうと、構わぬ。刺客だろうと、構わぬ。──その刃ごと、俺のものだ"}, {"t": "narrate", "text": "……わし、ではない。俺、と言いかけた。"}, {"t": "narrate", "text": "乱れている。この女ひとりに、わしの中の何かが、せり上がってきている。気に入らぬ。気に入らぬが──止まらぬ。"}, {"t": "sprite", "key": "dongzhuo_menace", "pos": "center"}, {"t": "say", "name": "董卓", "text": "呂布に賜るだと? 笑わせるな。わしが手放すと思うか。火が、掴んだ薪(まき)を返すか。──おまえが俺を殺しに来た獣なら、なおいい。媚びる女など反吐(へど)が出る。わしは、噛みつく獣が欲しい。対等に、わしの喉を狙える獣が"}, {"t": "say", "name": "董卓", "text": "殺せるものなら、殺してみろ。だがその前に──おまえの心を、わしが獲る"}, {"t": "sprite", "key": "diaochan_flustered", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "……ずるい、お方"}, {"t": "say", "name": "貂蝉", "text": "赦しもせず、憐れみもせず。……妾を、獲物だと言いながら、対等だと言う。そんな殺し方を、妾は……習っておりませぬ"}, {"t": "sprite", "key": "diaochan_killerlove", "pos": "center"}, {"t": "narrate", "text": "女の指が、わしの胸甲を掴んだ。爪が立つ。これは媚びの手ではない。縋(すが)る手だ──いや、まだ分からぬ。縋るふりかもしれぬ。罠の最終段かもしれぬ。"}, {"t": "narrate", "text": "だが、女の首筋が、燭火に染まって朱(あけ)に上気していくのを、芝居だとは、もう、思いたくなかった。"}, {"t": "narrate", "text": "──思いたくない。それが、すでに、わしの負けかもしれぬのに。"}, {"t": "narrate", "text": "わしは女の腰を抱き寄せた。熱い吐息が、喉に触れる。あと一寸、唇が──"}, {"t": "fx", "fx": "blackout"}, {"t": "narrate", "text": "……今宵は、ここまでにしてやる。先を急ぐ女は、たいてい何か隠している。"}, {"t": "jump", "goto": "ch4"}], "ch3_b": [{"t": "say", "name": "董卓", "text": "もうよい。刺客の真似はよせ。……わしが、許してやる"}, {"t": "fx", "fx": "cutin"}, {"t": "sprite", "key": "diaochan_coldeyes", "pos": "center"}, {"t": "narrate", "text": "言った瞬間、腕の中の体温が、すっと退(ひ)いた。"}, {"t": "say", "name": "貂蝉", "text": "……許す、と"}, {"t": "say", "name": "貂蝉", "text": "太師さまは、お優しいのですね。妾の喉に当たった刃を見て、震える女を憐れんでくださる。……ええ、とても、お優しい"}, {"t": "narrate", "text": "「優しい」と言われた。だが、その声は、墓石より冷たかった。"}, {"t": "say", "name": "貂蝉", "text": "(つまらぬ。この男も、結局は──妾を憐れんで、上に立ちたいだけ。赦すことで、許す側の席に座る。憐れみは、いちばん安い支配。……この太師も、ただの、男)"}, {"t": "narrate", "text": "何かを、しくじった。"}, {"t": "narrate", "text": "女の目が、わしを「格下」に置いた。媚びてもいないのに、媚びた者と同じ顔で扱われた。──赦しなど、求めていなかったのだ、この女は。対等を求めていた。憐れみを差し出した瞬間、わしは獣から、ただの「優しい老人」に落ちた。"}, {"t": "sprite", "key": "diaochan_fakesmile", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "……御酌を、続けても?"}, {"t": "narrate", "text": "笑みが、また貼り付いた。完璧な、作り物の笑みが。せっかく剥がれた素顔が、厚く塗り直された。遠い。"}, {"t": "jump", "goto": "ch4"}], "ch3_c": [{"t": "narrate", "text": "体温に溺れる前に、頭が動いた。李儒の囁きが、まだ耳の奥で鳴っている。逆用。鎖を、向け替える。"}, {"t": "say", "name": "董卓", "text": "李儒。──おまえの活路、乗ろう"}, {"t": "narrate", "text": "わしは女の涙を、いったん脇に置いた。惜しくはある。だが、惜しさで死んだ王は数多(あまた)いる。わしは、そうはならぬ。"}, {"t": "say", "name": "董卓", "text": "呂布には、わしから囁く。『おまえに貂蝉を約したのは誰だ』とな。恨みの矢じりは、王允の喉へ研いでおく。女が連環の糸を引くなら──その糸を手繰(たぐ)って、手元(てもと)を斬りに行く"}, {"t": "sprite", "key": "liju_scheming", "pos": "left"}, {"t": "say", "name": "李儒", "text": "御意。……ようやく、太師らしいお顔に戻られた"}, {"t": "narrate", "text": "あの女の喉に刃が光った夜、わしは恋に溺れかけた。だが溺れる男から先に死ぬ、それをこの乾いた謀臣が引き上げた。"}, {"t": "narrate", "text": "──覚えておけ。李儒。この活路を開いたのは、おまえだ。おまえの言を蹴る日が来れば、わしは北の掖門とやらで、若い戟に喉を裂かれるのだろう。"}, {"t": "narrate", "text": "だから今は聞く。"}, {"t": "narrate", "text": "寝所では女が泣いている。その涙が本物か芝居か、わしはまだ知らぬ。"}, {"t": "narrate", "text": "だが、鎖の構造は、もう、わしの掌(てのひら)にある。連環を、連環で討つ。王允、おまえの編んだ鎖で、おまえの首を縛ってやろう。"}, {"t": "jump", "goto": "ch4"}], "ch3_d": [{"t": "say", "name": "董卓", "text": "逃がさぬ。──おまえは刺客だ。ならば、刺客らしく、繋いでおく"}, {"t": "narrate", "text": "わしは武士を呼び、女の住まう楼に錠を増やさせた。窓に格子を、扉に番(ばん)を。物として、囲い込んだ。"}, {"t": "fx", "fx": "cutin"}, {"t": "sprite", "key": "diaochan_coldeyes", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "……繋ぐ、のですね"}, {"t": "say", "name": "貂蝉", "text": "(臆病。この男も、結局は怖いのだ。妾の刃が。だから鎖で縛る。──力で物を縛る男は、心を縛る術(すべ)を知らぬ。掴んだ気でいる。掴まれているのは、妾の体だけ。心は、いま、するりと抜けた)"}, {"t": "narrate", "text": "女は、抗(あらが)わなかった。それが、不気味だった。縛られた獣が、おとなしく牙を伏せるのは、次の一撃を待つときだけだ。"}, {"t": "narrate", "text": "──体は、確かに掌中にある。だが、心が、するりと逃げた感触がした。掴んだはずなのに、手の中が、空(から)だ。"}, {"t": "narrate", "text": "そして外の楼で、若い戟がこの噂を聞く。「太師は貂蝉を鎖で繋いだ」と。呂布の胸で、嫉妬がまた一段灼ける。"}, {"t": "jump", "goto": "ch4"}], "ch4": [{"t": "bg", "bg": "郿塢・太師の居室／黎明", "mood": "dawn"}, {"t": "narrate", "text": "郿塢（びお）。わしが築かせた、もう一つの長安だ。二十年の糧を積み、城壁は長安と同じ高さに上げた。ここに座っていれば、天が落ちても飢えはせぬ。"}, {"t": "narrate", "text": "だが今朝、わしの胸を温めているのは穀でも金でもない。隣で寝息を立てる、この女の体温だ。"}, {"t": "sprite", "key": "diaochan_base", "pos": "center"}, {"t": "narrate", "text": "貂蝉。王允がわしの足元に投げてよこした刃。十六の歌伎。半年、わしはこの刃を抱いて眠った。斬られるなら斬られてやる、と嘯きながら、未だ咽喉は無事だ。"}, {"t": "narrate", "text": "……無事すぎる、とも思う。"}, {"t": "say", "name": "李粛", "text": "太師——！太師に申し上げる。長安より、勅使にございます"}, {"t": "narrate", "text": "李肅。呂布と同郷の、わしが官を惜しんでやらなかった男だ。なぜこいつが勅使を名乗る。"}, {"t": "sprite", "key": "lisu_base", "pos": "left"}, {"t": "say", "name": "李粛", "text": "天子、御病ようやく癒え、未央殿にて群臣を会し——太師に、禅譲を望まれております。受禅の台、既に築き終えてございます"}, {"t": "sprite", "key": "lisu_kokuhaku", "pos": "center"}, {"t": "narrate", "text": "禅譲。"}, {"t": "narrate", "text": "……はは。"}, {"t": "narrate", "text": "ははははは。わしは寝床で起き上がり、腹の底から笑った。来たか。とうとう、漢の小僧がわしに玉座を差し出す日が来たか。"}, {"t": "say", "name": "董卓", "text": "台を、築いたと申すか"}, {"t": "say", "name": "李粛", "text": "百官、太師の入城を、首を長くして"}, {"t": "narrate", "text": "待っていた言葉だ。あまりに待っていたので、疑うことを忘れていた——いや。"}, {"t": "narrate", "text": "忘れたふりをした、と言うべきか。"}, {"t": "sprite", "key": "diaochan_fakesmile", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "……禅譲、と聞こえましたわ。太師。いえ——"}, {"t": "say", "name": "貂蝉", "text": "陛下、と。お呼びすればよろしいの？"}, {"t": "narrate", "text": "女の腕が、わしの首に巻きついた。薄衣ごしに、まだ寝起きの熱が移ってくる。耳のすぐ裏で、吐息が一つ。"}, {"t": "say", "name": "貂蝉", "text": "妾、太師が天下を獲られたら……何にしてくださるの"}, {"t": "say", "name": "董卓", "text": "何になりたい"}, {"t": "say", "name": "貂蝉", "text": "貴人"}, {"t": "narrate", "text": "即答だった。そして、笑った。目を細め、舌の先で唇を湿らせ、わしの顎を指の背でなぞる。"}, {"t": "say", "name": "董卓", "text": "よかろう。貴人にしてやる。天下の女がお前にひざまずく"}, {"t": "say", "name": "貂蝉", "text": "……嬉しい"}, {"t": "sprite", "key": "diaochan_killerlove", "pos": "center"}, {"t": "narrate", "text": "嬉しい、と言ったこの女の声に、今、間違いなく濡れたものがあった。芝居なら大したものだ。本物なら、もっと厄介だ。"}, {"t": "narrate", "text": "わしは知っている。この女が「嬉しい」と言う時ほど、その奥で刃を研いでいる音がする。半年で、それだけは学んだ。だが——学んだはずのわしが、なぜ今、この「嬉しい」を信じたがっている。"}, {"t": "narrate", "text": "信じたい、と思った瞬間に、もう負けかもしれぬ。落とすつもりが、落ちかけている。どちらが獲物だ、これは。"}, {"t": "fx", "fx": "blackout"}, {"t": "sprite", "key": "liju_insight", "pos": "left"}, {"t": "say", "name": "李儒", "text": "太師。……お喜びのところ、水を差します"}, {"t": "say", "name": "董卓", "text": "文優（李儒）。お前の顔は、いつも祝いに向かぬ"}, {"t": "say", "name": "李儒", "text": "李肅が勅使。受禅の台。あまりに、整いすぎております。台はいつ築いた。誰が見た。——王允の名が、この話のどこにも出ぬのが、わたしは怖い"}, {"t": "narrate", "text": "李儒。半年前から、こいつだけが同じことを言い続けている。あの女は刃だ、呂布に下げ渡せ、女に惑わされれば一門が滅ぶ、と。"}, {"t": "sprite", "key": "liju_remonstrate", "pos": "left"}, {"t": "say", "name": "李儒", "text": "太師。もう一度だけ申します。貂蝉を、呂布にお下げ渡しを。今ならまだ、奉先の戟は太師に向きませぬ。あの娘を境に、父子が割れております。割れた隙に、王允の手が伸びる"}, {"t": "narrate", "text": "李儒の声は、震えてはいない。震えていないからこそ、本気だと分かる。こいつは半年、一度も声を荒げず、ただ同じ穴を指差し続けてきた。"}, {"t": "choice", "options": [{"text": "「申せ、文優。お前の目が長安をどう見ているか、全部だ」", "d": {"liju": 2, "roken": 1}, "goto": "ch4_a"}, {"text": "「黙れ。二度同じことを言えば斬る、と言うたぞ。今日が天下取りだ、水を差すな」", "d": {"liju": -2, "rogan": 1}, "goto": "ch4_b"}, {"text": "「貂蝉を呂布に？……ならば文優、お前の妻を先に奉先にくれてやれ。できぬなら下がれ」", "d": {"liju": -1, "diaochan": 0}, "goto": "ch4_c"}]}], "ch4_a": [{"t": "sprite", "key": "liju_insight", "pos": "left"}, {"t": "say", "name": "李儒", "text": "……わたくしの手の者が、王允邸の下働きを一人、抱き込みました。王允は、同じ金冠を、二度贈っております。一度は呂布に。一度は太師に。同じ娘を、二人に『許した』のです"}, {"t": "say", "name": "董卓", "text": "……ほう"}, {"t": "say", "name": "李儒", "text": "連環、と申します。鎖で繋いだ二頭を、互いに食い合わせる計。太師と奉先のあいだに置かれた鎖が——"}, {"t": "narrate", "text": "李儒の視線が、ちらと、奥の薄衣へ流れた。"}, {"t": "say", "name": "李儒", "text": "……あの娘で、ございます"}, {"t": "narrate", "text": "部屋の温度が、すっと下がった気がした。背後の女は、何も言わぬ。寝起きの猫のように、ただ静かに、わしの広い背に頬を寄せている。"}, {"t": "sprite", "key": "diaochan_killerlove", "pos": "center"}, {"t": "narrate", "text": "この背に頬を寄せている女が、わしと奉先を食い合わせる鎖だと、李儒は言う。半年抱いて眠った刃の根が、ようやく見えた。"}, {"t": "narrate", "text": "……見えてなお、わしはこの女を斬る気にならぬ。それが惚れなのか、ただの強情なのか、わし自身、もう分からん。"}, {"t": "sprite", "key": "liju_insight", "pos": "center"}, {"t": "say", "name": "董卓", "text": "文優。お前の目は、確かに長安で一番よく見える"}, {"t": "say", "name": "李儒", "text": "では"}, {"t": "sprite", "key": "liju_lament", "pos": "center"}, {"t": "say", "name": "董卓", "text": "だが今日、わしは台へ上る。鎖を断つのは、玉座に座ってからでも遅うない。——お前の見たものは、忘れぬ。それだけは約束する"}, {"t": "narrate", "text": "この「忘れぬ」が、後でわしの命を一度だけ救うことになるとは、この時のわしは知らぬ。"}, {"t": "jump", "goto": "ch4_cont"}], "ch4_b": [{"t": "fx", "fx": "cutin"}, {"t": "say", "name": "董卓", "text": "下がれ、文優ッ"}, {"t": "sprite", "key": "liju_lament", "pos": "left"}, {"t": "narrate", "text": "李儒は拱手を解き、深く一礼すると、背を向けた。戸口で一度だけ立ち止まり、天井——その向こうの天を、仰いだ。"}, {"t": "say", "name": "李儒", "text": "……吾等、皆。婦人の手にかかって、死ぬのでしょうな"}, {"t": "narrate", "text": "独り言のように、こいつは言った。わしに聞かせる気もない声で。"}, {"t": "narrate", "text": "婦人の手。馬鹿を申せ。わしを殺せる手など、この天下に呂布の戟が一つあるきりだ。女の細腕に何ができる。"}, {"t": "narrate", "text": "——そう吐き捨てた、わしの背に。ふたたび、温かい腕が巻きついた。"}, {"t": "sprite", "key": "diaochan_fakesmile", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "あの方、いつも妾を、嫌っておいでね"}, {"t": "say", "name": "董卓", "text": "お前が刃だからだ"}, {"t": "sprite", "key": "diaochan_killerlove", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "……ふふ。太師は、妾を刃と知って、抱いて寝るの"}, {"t": "say", "name": "董卓", "text": "知って抱くから、面白い"}, {"t": "narrate", "text": "女の睫毛が、伏せられた。その奥で何が動いたか、わしには見えなかった。見えなかったことに、なぜか胸が騒いだ。"}, {"t": "jump", "goto": "ch4_cont"}], "ch4_c": [{"t": "fx", "fx": "cutin"}, {"t": "say", "name": "董卓", "text": "下がれ、文優ッ"}, {"t": "sprite", "key": "liju_lament", "pos": "left"}, {"t": "narrate", "text": "李儒は拱手を解き、深く一礼すると、背を向けた。戸口で一度だけ立ち止まり、天井——その向こうの天を、仰いだ。"}, {"t": "say", "name": "李儒", "text": "……吾等、皆。婦人の手にかかって、死ぬのでしょうな"}, {"t": "narrate", "text": "独り言のように、こいつは言った。わしに聞かせる気もない声で。"}, {"t": "narrate", "text": "婦人の手。馬鹿を申せ。わしを殺せる手など、この天下に呂布の戟が一つあるきりだ。女の細腕に何ができる。"}, {"t": "narrate", "text": "——そう吐き捨てた、わしの背に。ふたたび、温かい腕が巻きついた。"}, {"t": "sprite", "key": "diaochan_fakesmile", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "あの方、いつも妾を、嫌っておいでね"}, {"t": "say", "name": "董卓", "text": "お前が刃だからだ"}, {"t": "say", "name": "貂蝉", "text": "……ふふ。太師は、妾を刃と知って、抱いて寝るの"}, {"t": "say", "name": "董卓", "text": "知って抱くから、面白い"}, {"t": "sprite", "key": "diaochan_killerlove", "pos": "center"}, {"t": "narrate", "text": "女の睫毛が、伏せられた。その奥で何が動いたか、わしには見えなかった。見えなかったことに、なぜか胸が騒いだ。"}, {"t": "jump", "goto": "ch4_cont"}], "ch4_cont": [{"t": "bg", "bg": "郿塢〜長安・街道／曇天", "mood": "cool"}, {"t": "narrate", "text": "車を仕立てた。貂蝉を隣に乗せ、長安へ向かう。沿道に兵を並べ、わしの即位を待つ百官の顔を思い描けば、悪くない朝だ。"}, {"t": "narrate", "text": "——だが、街道に出てすぐ。"}, {"t": "narrate", "text": "車輪が、折れた。前の左輪が、何もない平らな道で、ひとりでに裂けた。"}, {"t": "say", "name": "董卓", "text": "……車を替えよ"}, {"t": "narrate", "text": "替えた。馬に乗り換える。走り出して、いくらも行かぬうちに——"}, {"t": "narrate", "text": "馬が、手綱を食い千切った。轡を噛み砕き、口から血の泡を吹いて、棹立ちになった。"}, {"t": "narrate", "text": "わしは落馬こそせなんだが、地に足をついた時、ほんの一瞬、足の裏から何かが這い上がった。寒さに似た、しかし寒さではないもの。"}, {"t": "sprite", "key": "diaochan_coldeyes", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "太師。お顔の色が"}, {"t": "say", "name": "董卓", "text": "気のせいだ"}, {"t": "say", "name": "貂蝉", "text": "ええ。きっと、気のせい"}, {"t": "narrate", "text": "この女は、何も驚いていない。車輪が折れても、馬が狂っても、まるで——筋書きを、先に読んでいたかのように。"}, {"t": "narrate", "text": "……いや。考えすぎだ。考えすぎだと、思いたい。"}, {"t": "narrate", "text": "道端で、童(わらべ)らが歌っていた。痩せた、薄汚れた子らだ。何という歌だと耳を澄ませ——"}, {"t": "narrate", "text": "「千里草、何ぞ青青たる。十日の上、生を得ず——」"}, {"t": "fx", "fx": "flash"}, {"t": "narrate", "text": "千里草。十日上。"}, {"t": "narrate", "text": "草冠に千里——董。十日の上——卓。"}, {"t": "narrate", "text": "わしの名だ。董卓は、生を得ず。子らが、わしの死を歌っている。"}, {"t": "say", "name": "董卓", "text": "……誰が教えた、その歌を"}, {"t": "narrate", "text": "童らは、わしの怒声に蜘蛛の子のように散った。誰も答えぬ。歌だけが、風に残った。"}, {"t": "narrate", "text": "道の真ん中に、青い袍、白い巾の道人が立っていた。竿の先に長い白布を結び、布の両端に、墨で大きく「口」の字。「口」が、二つ。"}, {"t": "narrate", "text": "呂。"}, {"t": "narrate", "text": "口、口で、呂。呂布の、呂。"}, {"t": "say", "name": "董卓", "text": "あの道人を捕えよ——"}, {"t": "narrate", "text": "兵が駆けた時には、もう、誰もいなかった。竿だけが、道に倒れていた。"}, {"t": "narrate", "text": "わしは火だ。天下のどんな凶兆も、火に焼べればただの灰だ。——そう己に言い聞かせながら、わしは、隣の女の手を、無意識に握っていた。"}, {"t": "narrate", "text": "女は、握り返してきた。冷たくなかった。むしろ、温かかった。その温かさが、今日に限って、なぜか怖い。"}, {"t": "sprite", "key": "diaochan_fakesmile", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "……怖いの？太師"}, {"t": "say", "name": "董卓", "text": "わしが、誰に"}, {"t": "say", "name": "貂蝉", "text": "ふふ。なら、なぜ妾の手を、こんなに強く"}, {"t": "narrate", "text": "俺は——"}, {"t": "narrate", "text": "俺は、と。今、わし、ではなく、俺、と言いかけた。胸の内でだ。"}, {"t": "narrate", "text": "乱れている。たかが女の手の温みに、董仲穎の自我が、ほつれかけている。半年抱いて、ついぞ揺れなんだものが、今日この道の上で。"}, {"t": "narrate", "text": "……認めよう。わしは、この女に心を握られかけている。握り返してきたこの手が、芝居だとしても。芝居でないとしても。どちらでも、もう遅い気がする。"}, {"t": "bg", "bg": "長安・北掖門前／黄昏、血のような空", "mood": "fire"}, {"t": "narrate", "text": "長安に着いた。百官が、首を長くして待っているはずの城門に。"}, {"t": "narrate", "text": "——歓呼が、ない。"}, {"t": "narrate", "text": "受禅の台へ向かう道、北掖門。両側に、群臣が立ち並んでいる。立ち並んで、いるのに。誰も、わしを見て笑わぬ。誰の手にも、笏ではなく——"}, {"t": "fx", "fx": "cutin"}, {"t": "narrate", "text": "抜き身の、剣。"}, {"t": "sprite", "key": "wangyun_resolved", "pos": "center"}, {"t": "say", "name": "王允", "text": "——反賊、ここに至れり"}, {"t": "narrate", "text": "王允。貂蝉をわしに献じた、あの腰の低い司徒が。背筋を伸ばし、声を張り上げた。半年、こいつの作り笑いの下に、この声があったのか。"}, {"t": "say", "name": "王允", "text": "武士は、何処(いずこ)にあるか——ッ！"}, {"t": "narrate", "text": "門の左右から、伏兵。戟、槊、百を超える穂先が、わしへ殺到した。"}, {"t": "say", "name": "董卓", "text": "謀ったなァ——！！"}, {"t": "narrate", "text": "だが、わしは火だ。金冠の下、肌に鎧を着込んでいる。穂先は鎧を噛んで滑り、わしの肉までは届かぬ。一本が腕を裂いた。それだけだ。たかが、それだけ。"}, {"t": "narrate", "text": "わしは車から転げ落ち、地を蹴って起き上がった。血が一筋、腕を伝う。周りは敵。だが、一人だけ、わしが呼べば必ず来る男がいる。半年、わしの背後を守り、わしを「父」と呼んだ、天下無双の——"}, {"t": "say", "name": "董卓", "text": "吾が子、奉先(ほうせん)は——何処にあるッ！！"}, {"t": "fx", "fx": "blackout"}, {"t": "sprite", "key": "lvbu_base", "pos": "center"}, {"t": "narrate", "text": "来た。"}, {"t": "narrate", "text": "車の後ろから、影が立ち上がる。方天画戟。逆光で、奉先の顔は見えぬ。見えぬが、あの体躯を、あの戟の重みを、わしが見間違うはずがない。"}, {"t": "narrate", "text": "来てくれた。やはり来てくれた。わが子は——"}, {"t": "say", "name": "呂布", "text": "……詔(みことのり)あり"}, {"t": "narrate", "text": "……何。"}, {"t": "sprite", "key": "lvbu_battlecry", "pos": "center"}, {"t": "say", "name": "呂布", "text": "賊を、討つ——ッ！！"}, {"t": "narrate", "text": "戟の穂先が、わしを向いた。わしを、向いた。"}, {"t": "narrate", "text": "半年。あの女を巡って、わしと奉先のあいだに、確かに一本、目に見えぬ鎖が架かっていた。李儒が指差し続けた、あの鎖だ。鎖の片端をわしが握り、片端を——この女が握って、ゆっくりと、引いていた。"}, {"t": "sprite", "key": "diaochan_killerlove", "pos": "center"}, {"t": "narrate", "text": "貂蝉は、斬りに来ぬ。半年、わしの咽喉に届く距離にいて、ついぞ自らの手では刺さなかったこの女は、今も、ただ車の中から、わしと奉先を見ている。"}, {"t": "narrate", "text": "その瞳に、殺意がある。確かに、ある。生きながらわしの肉を噛みちぎりたいと言った、あの殺意だ。"}, {"t": "narrate", "text": "——だが、その殺意の奥に、もう一つ。わしには名のつけられぬ、別の色が、揺れている。"}, {"t": "narrate", "text": "芝居か。本心か。半年宙吊りにされ続けた、その問いの答えが、今、この門の上で、決まろうとしている。"}, {"t": "narrate", "text": "奉先の戟が、構えきる。王允が、貂蝉が、李儒が、千里草の歌が、口口の道人が、全部、この一瞬に集まってくる。"}, {"t": "narrate", "text": "わしは火だ。獅子だ。最期まで、荒ぶる獣の王だ。命乞いはせぬ。だが——"}, {"t": "narrate", "text": "奉先。お前の、その嫉妬に。わしは、どう臨む。"}, {"t": "fx", "fx": "cutin"}, {"t": "choice", "options": [{"text": "戟の前に立ちはだかり、奉先の目を見据えて吼える——「その女は、王允がお前にもくれてやった駒だ。お前も、わしも、二度贈られた金冠で繋がれた、同じ鎖の上だ。斬るなら王允を斬れ、奉先ッ」", "d": {}, "goto": "ch4_d"}, {"text": "退かぬ。嫌(いや)と言うなら来い、奉先。父を超えてみよ——わしも獣、お前も獣。ならば力で決する。戟には、わしの牙で応えてやる", "d": {}, "goto": "ch4_e"}]}], "ch4_d": [{"t": "narrate", "text": "〔貂蝉MAX×（連環露見 高 or 李儒信頼 高）が揃うなら→ 李儒のウルトラC(反・連環計)が起動。鎖の真実が奉先を貫き、戟が王允へ向き替わる〕"}, {"t": "fx", "fx": "flash"}, {"t": "fx", "fx": "blackout"}, {"t": "narrate", "text": "——力こそ、正義。わしはそう言って、ここまで来た。"}, {"t": "narrate", "text": "その正義の果てで、わしを生かすも殺すも、たった一人の女の、たった一つの心が、握っている。"}, {"t": "narrate", "text": "笑えるな、奉先。わしを殺せるのは、お前の戟だと思っていた。違った。お前の戟を動かすのは、あの女の——"}, {"t": "narrate", "text": "さあ。落とせたのか、わしは。それとも、落とされていたのは。"}, {"t": "jump", "goto": "__resolve_reconcile__"}], "ch4_e": [{"t": "narrate", "text": "〔貂蝉MAXなら→ 呂布を力で討つ。生存し天下を握るが、無双の臣を喪う〕"}, {"t": "fx", "fx": "flash"}, {"t": "fx", "fx": "blackout"}, {"t": "narrate", "text": "——力こそ、正義。わしはそう言って、ここまで来た。"}, {"t": "narrate", "text": "その正義の果てで、わしを生かすも殺すも、たった一人の女の、たった一つの心が、握っている。"}, {"t": "narrate", "text": "笑えるな、奉先。わしを殺せるのは、お前の戟だと思っていた。違った。お前の戟を動かすのは、あの女の——"}, {"t": "narrate", "text": "さあ。落とせたのか、わしは。それとも、落とされていたのは。"}, {"t": "jump", "goto": "__resolve_kill__"}], "BIYOKU": [{"t": "bg", "bg": "北掖門・未明（黒い甍、青ざめた天、篝火の点々）", "mood": "cool"}, {"t": "narrate", "text": "受禅台を築いたと、あの童顔の李肅が言った。天子がわしに禅を譲ると。郿塢を出てから車輪が一度折れ、馬が手綱を噛み切った。童(わらべ)が歌っていた——千里草、何ぞ青青たる、十日の上、生を得ず、と。"}, {"t": "narrate", "text": "凶兆だらけよ。並の男なら引き返す。だがわしは火だ。火が己の燃える音を恐れてどうする。"}, {"t": "narrate", "text": "……それでも。隣に座る女の指先が、わしの袖を、いつもより強く握っている。それが本物の不安か、わしを油断させるための芝居か——わしには、まだ、分からん。"}, {"t": "sprite", "key": "diaochan_killerlove", "pos": "right"}, {"t": "say", "name": "貂蝉", "text": "太師。……今日は、なぜか、胸がさわぐのです"}, {"t": "narrate", "text": "さわぐ、か。お前の胸が本当にさわいでいるのか、それとも「さわいでいる」とわしに言わせたいのか。十六の歌伎が、その二つを同じ顔でやってのける。"}, {"t": "say", "name": "董卓", "text": "わしが貴妃にしてやると言うたのだ。胸がさわぐのは当たり前よ。天に昇るのだからな"}, {"t": "say", "name": "貂蝉", "text": "……ええ。天に、昇るのですわね"}, {"t": "narrate", "text": "その目が、ほんの一瞬、わしを哀れんだように見えた。哀れみ。獲物が獲物を哀れむか。罠かもしれぬ。罠だろう。——だが、信じたい己が、腹の底で、火の粉のように爆ぜた。"}, {"t": "bg", "bg": "北掖門・門前（宝剣の列、白刃が篝火を返す）", "mood": "cool"}, {"t": "fx", "fx": "blackout"}, {"t": "fx", "fx": "flash"}, {"t": "narrate", "text": "門をくぐった。その刹那——両側の物陰から、宝剣と戟槊の列が、ぬっと立ち上がった。"}, {"t": "sprite", "key": "wangyun_scheme", "pos": "center"}, {"t": "say", "name": "王允", "text": "反賊、ここに至れり——！　武士はいずこ、太師を討て——！"}, {"t": "narrate", "text": "来た。芝居の幕が、いま、剥がれた。連環計。王允の。この爺が、すべての糸を引いていた。"}, {"t": "narrate", "text": "だがな、王允。——わしは、知っていたぞ。"}, {"t": "sprite", "key": "dongzhuo_menace", "pos": "center"}, {"t": "say", "name": "董卓", "text": "ぬるいわ……ッ！"}, {"t": "narrate", "text": "鎧は、着込んでいる。李儒が、口を酸っぱくして言うておった——「郿塢を出る日は、必ず鎧を。理由は問わず」と。あの男の慧眼を、今日ばかりは、わしは蹴らなかった。"}, {"t": "narrate", "text": "腕に一筋、熱が走る。傷だ。だが咽喉(のど)は無事。わしは車から落ちず、立っている。立って、吼える番だ。"}, {"t": "bg", "bg": "北掖門・門内（伏兵に囲まれた一点、その奥に呂布の影）", "mood": "cool"}, {"t": "fx", "fx": "cutin"}, {"t": "sprite", "key": "lvbu_battlecry", "pos": "center"}, {"t": "say", "name": "呂布", "text": "詔(みことのり)あり——賊を、討つ……！"}, {"t": "narrate", "text": "来たな、奉先。わしの息子。わしの牙。その牙を、王允は、見事に研ぎ直した。貂蝉という砥石で。"}, {"t": "narrate", "text": "並の死に方なら、ここでお前の戟がわしの咽喉を貫く。それが、本来の幕切れだったのだろう。——だが、わしは並ではない。そして、李儒が、もう一つ仕込んでいた。「呂布に、全部を、見せてやれ」と。"}, {"t": "say", "name": "董卓", "text": "奉先。戟を止めよ。止めぬなら、その前に——耳だけ、貸せ"}, {"t": "say", "name": "呂布", "text": "黙れ老賊ッ、貂蝉を奪った貴様に——"}, {"t": "say", "name": "董卓", "text": "その貂蝉を、お前に『許嫁』と偽って差し出したのは、誰だ"}, {"t": "narrate", "text": "呂布の戟が、止まった。ほんの、半歩。だが半歩あれば、火は入る。"}, {"t": "say", "name": "董卓", "text": "金冠を贈ったのは王允だな。次に、その同じ女を、わしに献じたのも王允だ。一人の女を、二人の男に。——奉先、お前は気づかなんだか。お前の嫉妬は、お前の怒りは、はじめから、あの痩せ爺の掌(てのひら)の上で、踊らされていただけだということに"}, {"t": "sprite", "key": "wangyun_desperate", "pos": "center"}, {"t": "say", "name": "王允", "text": "惑わされるな呂布将軍ッ、それは賊の——"}, {"t": "say", "name": "董卓", "text": "許嫁と偽り、使い捨てた。お前も。貂蝉も。王允にとっては、二人とも、わしを刺すための、ただの駒よ"}, {"t": "narrate", "text": "連環計。輪を連ねる計。だが輪というのはな、王允——閉じれば、最後は、輪を投げた者自身の首に、戻ってくるのよ。"}, {"t": "bg", "bg": "北掖門・門内（董卓と呂布の間、貂蝉が一歩、踏み出す）", "mood": "cool"}, {"t": "narrate", "text": "そのとき、貂蝉が動いた。"}, {"t": "narrate", "text": "わしは、息を呑んだ。——来る、と思った。この女の本性が。連環の最後の一手。今この瞬間こそ、貂蝉が王允の駒として、わしの隙を呂布に売り渡す瞬間だと。"}, {"t": "narrate", "text": "早すぎる甘えは疑え。涙は武器だ。しなだれは罠だ。さんざん己に言い聞かせてきた。だから——身構えた。獣のように。"}, {"t": "narrate", "text": "だが、貂蝉は。"}, {"t": "sprite", "key": "diaochan_tears", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "将軍。……妾(わたし)は、ここにおります"}, {"t": "narrate", "text": "貂蝉は、わしの側へ、半歩、踏み出した。呂布と、わしと。その二つの間に引かれた線の、わしの側へ。誰に強いられたでもなく。"}, {"t": "say", "name": "貂蝉", "text": "司徒様は、妾に申されました。『太師に近づき、隙を作れ。お前は呂布将軍の妻になる女だ』と。妾は、万死も辞さぬと誓いました。……本当に、誓ったのです"}, {"t": "say", "name": "呂布", "text": "ならば——なぜっ"}, {"t": "say", "name": "貂蝉", "text": "分かりませぬ。……いつからか、妾の涙が、芝居でなくなっておりました。いつ、かは、妾にも、分かりませぬ"}, {"t": "fx", "fx": "flash"}, {"t": "narrate", "text": "……俺は。"}, {"t": "narrate", "text": "わし、ではない。俺、と漏れた。この女の一言で、わしの自我の、いちばん古い箍(たが)が、軋んでいる。"}, {"t": "narrate", "text": "いつからか、芝居でなくなっていた。それが、本物の告白なのか。それとも、呂布の戟をわしから逸らすための、連環の、さらにその上を行く、最後の芝居なのか。——分からん。最後まで、分からん。たぶん、この女自身にも。"}, {"t": "narrate", "text": "だが、今この刹那、貂蝉は、わしの側に、立っている。それだけは、事実だ。"}, {"t": "bg", "bg": "北掖門・門内（呂布の戟、ゆっくりと向きを変える）", "mood": "cool"}, {"t": "fx", "fx": "cutin"}, {"t": "sprite", "key": "lvbu_betrayed", "pos": "center"}, {"t": "narrate", "text": "呂布の眼の色が、変わった。"}, {"t": "narrate", "text": "嫉妬という火は、行き場を求める。わしへ向けられた火だった。だがその火を焚きつけた者が、わしではなく、門の上で勝ち誇っていた痩せ爺だと知ったとき——火は、向きを、変える。"}, {"t": "say", "name": "呂布", "text": "……王允……ッ。貴様は俺に、貂蝉を……許嫁と……"}, {"t": "say", "name": "王允", "text": "ま、待て呂布将軍ッ、大義のためだ、董卓を討てば天下は——"}, {"t": "say", "name": "呂布", "text": "俺の女を駒にした男の、どこが、大義だ——ッ！！"}, {"t": "fx", "fx": "flash"}, {"t": "narrate", "text": "方天画戟が、翻った。わしの咽喉へ——ではない。門の上、連環を投げた黒幕、王允の側へ。"}, {"t": "narrate", "text": "笑えてくるわ。連環計よ。一人の女で二人の男を狂わせ、噛み合わせ、共に喰らう計。——だが、その輪は、いま、王允自身の咽喉を、喰らいに、昇っていく。"}, {"t": "sprite", "key": "dongzhuo_laugh", "pos": "center"}, {"t": "say", "name": "董卓", "text": "ははっ……ははははは——ッ！！　見たか王允ッ！　お前の輪が、お前の首に、還ったわッ！"}, {"t": "narrate", "text": "わしは退かぬ。鎧を着込み、傷ついた腕で、車上に立ち、吼える。獣のまま。最後まで、火のまま。陰謀を陰謀で出し抜いたのではない。嘘のない者の側へ、わしの牙(呂布)を、引き戻しただけよ。"}, {"t": "bg", "bg": "北掖門・夜明け前（伏兵、崩れ散る。王允、捕らわれる）", "mood": "dawn"}, {"t": "narrate", "text": "黒幕を喰った輪は、ほどけた。号令を失った伏兵は、烏合の衆よ。王允は捕らえられ、青ざめて喚いていたが——わしは、聞かぬ。"}, {"t": "narrate", "text": "情けはかけぬ。わしは、わしを刺そうとした爺に、微笑んでやる男ではない。それをやれば、わしはわしでなくなる。そして、わしでなくなった男に、この女は、一瞬で冷める。それを、わしは、もう、知っている。"}, {"t": "say", "name": "董卓", "text": "李儒を呼べ"}, {"t": "narrate", "text": "あの童顔の謀臣が、生きて、駆けてくるだろう。「われら皆、女の手にかかって死ぬぞ」と天を仰いで嘆いた、ただ一人の慧眼。——その嘆きを、今日、わしは、裏切ってやった。鎧を着込めと言うた男の言葉を、蹴らなかった。それだけのことよ。礼は、一言で足りる。「お前の目は、正しかった」と。それ以上は、言うてやらぬ。男に媚びるのは、女に媚びるより、みっともない。"}, {"t": "bg", "bg": "北掖門・払暁（東の天、わずかに焼ける）", "mood": "dawn"}, {"t": "sprite", "key": "diaochan_tears", "pos": "right"}, {"t": "narrate", "text": "払暁の光が、女の頬を撫でた。作り笑いの仮面は、もう、ない。涙の痕が、化粧を溶かして、生身の温度を、剥き出しにしている。"}, {"t": "narrate", "text": "わしは、その細い顎を、傷ついた手で、掬い上げた。血の匂いと、女の香が、混ざる。吐息が、わしの指に触れて、熱い。これは芝居ではない、と——肌が、言う。だが肌など、いくらでも、騙せる。十六の歌伎なら、なおさら。"}, {"t": "say", "name": "貂蝉", "text": "……太師。妾を、斬りませぬのか。妾は、あなたを、殺しに来た女ですわ"}, {"t": "say", "name": "董卓", "text": "斬らぬ。お前は、わしを殺しに来て、わしを生かした女だ。そんな珍品を、斬る馬鹿がおるか"}, {"t": "sprite", "key": "diaochan_truesmile", "pos": "center"}, {"t": "narrate", "text": "女が、笑った。今度は、作り笑いではない——と、思いたい。思いたい、というその一語が、わしの内に、まだ、刃のように、刺さったまま、抜けぬ。それでよい。抜けぬまま、抱く。それが、この女を抱く、唯一の作法よ。"}, {"t": "narrate", "text": "唇が、近い。吐息が、まじる。が——ここまでだ。火は、燃え盛るほど、芯を見せぬ。続きは、この払暁の光の、届かぬところで。"}, {"t": "bg", "bg": "北掖門・日の出（焼ける天、董卓の影、長く伸びる）", "mood": "dawn"}, {"t": "narrate", "text": "わしは、奪う男だ。欲しいと言えば奪い、殺すと言えば殺す。これからも、それは、変わらん。天下も、玉座も、この手で、ねじ伏せて獲る。"}, {"t": "narrate", "text": "この女の心だけは——奪った、とは、言うまい。力で獲ろうとした心が、たまたま、今日、わしに牙を返さなかった。ただ、それだけのことよ。明日も返さぬ保証など、どこにもない。隣に座るこの女が、本物の惚れを抱いているのか、それとも、まだ、もっと深い連環の、途中なのか——わしは、死ぬまで、確かめ切れぬのだろう。"}, {"t": "narrate", "text": "恋が、わしの火を正しくしたのではない。火は、はじめから正しい。恋は、ただ、火のそばに、危うい刃を、一振り、置いていっただけよ。"}, {"t": "narrate", "text": "——上等だ。"}, {"t": "say", "name": "董卓", "text": "貂蝉"}, {"t": "say", "name": "貂蝉", "text": "はい、太師"}, {"t": "say", "name": "董卓", "text": "お前の刃、生涯、わしの傍らに、置いておけ。いつわしを刺すか分からぬ刃ほど、抱いて面白いものはない"}, {"t": "sprite", "key": "diaochan_killerlove", "pos": "right"}, {"t": "say", "name": "貂蝉", "text": "……ふふ。仰せのままに。——いつか、本当に、刺してしまうかもしれませんわよ"}, {"t": "say", "name": "董卓", "text": "そのときは、わしの咽喉を、お前の手で、な。王允の戟になど、二度と、くれてやらぬ"}, {"t": "narrate", "text": "女は、答えなかった。ただ、わしの肩に、頭を、預けた。その重さが、本物か、罠か。——わしは、笑った。獣の、まま。"}, {"t": "narrate", "text": "火は、消えなかった。傍らに、一振りの刃を抱いて、なお、焚(も)える。"}, {"t": "narrate", "text": "……これが、わしの、勝ちよ。万に一つの、綱渡りの。"}, {"t": "fx", "fx": "blackout"}, {"t": "ending", "id": "BIYOKU", "title": "焚天 ─ 相国董卓伝／【比翼】真・生存エンド"}], "KOOU": [{"t": "bg", "bg": "北掖門・夜", "mood": "night"}, {"t": "narrate", "text": "受禅台が築かれたと聞いた。天子がわしに位を譲ると。"}, {"t": "narrate", "text": "李肅が偽の詔を捧げて笑った。郿塢を出る朝、車輪が一つ折れた。道で馬が手綱を断った。童(わらべ)が歌っていた——「千里草、何ぞ青青たる、十日の上、生を得ず」と。"}, {"t": "narrate", "text": "凶兆だ。わしは知っている。李儒が幾度も言った。あの女を呂布に下げ渡せ、女に惑わされるな、一門が滅ぶ、と。二度言うなら斬る、とわしは脅した。あの男は天を仰いで嘆いた——「われら皆、婦人の手にかかって死ぬぞ」と。"}, {"t": "narrate", "text": "わしはそれを蹴った。だが——蹴りながら、刃の在処だけは数えていた。獣は、罠を笑って踏むが、踏む前に必ず牙を研いでおくものだ。"}, {"t": "sprite", "key": "diaochan_base", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "太師。……今宵、わたくしは貴妃になるのですね"}, {"t": "narrate", "text": "わしの腕に、女の体温が一つ預けられている。柔く、重く、香(かぐわ)しい。これが芝居なら、天下一の芝居師だ。これが本物なら、天下一の業(ごう)だ。"}, {"t": "narrate", "text": "どちらでもいい——と、近頃わしはそう思うようになっていた。それがこの女に「落とされた」ということなのか、この女を「落とした」ということなのか、もう境目が分からぬ。"}, {"t": "sprite", "key": "diaochan_killerlove", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "……怖いお顔。何を見ておいでです、わたくしの上の、どこか遠くを"}, {"t": "narrate", "text": "見透かされている。いつもこの女はわしの底を覗く。覗いて、わずかに笑う。その笑みが、惚れた女の笑みなのか、獲物を仕留める寸前の刺客の笑みなのか——わしはとうに見分けるのをやめた。"}, {"t": "say", "name": "董卓", "text": "奉先がな、近頃わしを見る目が変わった"}, {"t": "sprite", "key": "diaochan_flustered", "pos": "center"}, {"t": "narrate", "text": "女の睫毛が、一度だけ震えた。芝居なら見事に震わせたものだ。本物なら、それは——いや、考えるな。"}, {"t": "say", "name": "貂蝉", "text": "……呂将軍が、何か"}, {"t": "say", "name": "董卓", "text": "お前を見る目だ。あれは、わしの牛を盗もうとする目だ"}, {"t": "narrate", "text": "殿門をくぐった。その刹那、左右の闇が一斉に立ち上がった。"}, {"t": "say", "name": "王允", "text": "反賊ここに至れり——武士はいずこか!"}, {"t": "fx", "fx": "flash"}, {"t": "narrate", "text": "戟が来た。槊が来た。百の穂先が車のわしへ殺到する。"}, {"t": "narrate", "text": "だがわしは——笑っていた。鎧を着込んでいる。布の下に、いつも。罠を笑って踏む獣は、牙を研いでおくと言ったろう。"}, {"t": "say", "name": "董卓", "text": "ぬるいわ、王允ッ!!"}, {"t": "narrate", "text": "腕を一つ裂かれた。それだけだ。揺れた車から、わしは石畳へ転げ落ちた。落ちながら、もう答えを知っていた。この茶番を終わらせる者の名を。"}, {"t": "say", "name": "董卓", "text": "吾が子・奉先! 奉先はいずこかッ!!"}, {"t": "narrate", "text": "呼んだ。わしの最強の刃。わしが拾い、わしが育て、わしが「子」と呼んだ唯一の獣。あれが来れば、この百余など藁だ。あれが来れば——"}, {"t": "sprite", "key": "lvbu_cold", "pos": "center"}, {"t": "say", "name": "呂布", "text": "……詔あり"}, {"t": "narrate", "text": "来た。"}, {"t": "say", "name": "呂布", "text": "賊を、討つ"}, {"t": "fx", "fx": "blackout"}, {"t": "narrate", "text": "時が止まった。"}, {"t": "narrate", "text": "奉先の戟の穂先が、わしの咽喉へ向いていた。味方の戟だ。わしの牛を盗もうとする目をした、わしの子の戟だ。"}, {"t": "narrate", "text": "——ああ。盗まれたのは牛ではない。"}, {"t": "fx", "fx": "cutin"}, {"t": "sprite", "key": "lvbu_betrayed", "pos": "center"}, {"t": "say", "name": "呂布", "text": "太師は……貂蝉を、返さなかった"}, {"t": "narrate", "text": "そうだ。返さなかった。李儒が幾度も言った。「貂蝉を呂布に賜れ、さもなくば一門が滅ぶ」と。わしは斬ると脅して退けた。"}, {"t": "narrate", "text": "わしは知っていて、なお返さなかった。女ひとりを。この、芝居か本物かも分からぬ女ひとりを。"}, {"t": "say", "name": "呂布", "text": "だから——俺(おれ)が、奪う"}, {"t": "narrate", "text": "戟が来る。"}, {"t": "narrate", "text": "……ここでわしは、選ぶ。"}, {"t": "narrate", "text": "——詫びる? 馬鹿を言え。わしは董卓だ。奪うと言って奪い、殺すと言って殺す。詫びた瞬間、この女の目から灯が消えるのを、わしは何度も見てきた。媚びる男は、この女の獲物だ。獲物にはなれぬ。"}, {"t": "say", "name": "董卓", "text": "奉先ッ! お前の女ではないわ——"}, {"t": "fx", "fx": "cutin"}, {"t": "say", "name": "董卓", "text": "わしの、女だッ!!!"}, {"t": "narrate", "text": "弾いた。あの方天画戟を、転がりざまの片腕一本で、わしは弾き上げた。"}, {"t": "narrate", "text": "五十を越えた肥えた老体だと? 笑わせるな。わしは涼州で羌を素手でねじ伏せた、董仲穎(とうちゅうえい)だ。火だ。燃え盛る火に、刃の年齢(とし)など関係あるか。"}, {"t": "narrate", "text": "立ち上がりざま、わしは吼えた。腕の傷から血が滴る。だが滴る血すら、松明に灼かれて熱い。"}, {"t": "say", "name": "董卓", "text": "李肅ぅ! 王允ぅ! 貴様らの茶番は——よくできていたわ! だがな、火を消すには、火より大きな火が要るのだ!!"}, {"t": "bg", "bg": "北掖門・乱戦", "mood": "fire"}, {"t": "sprite", "key": "lvbu_rage", "pos": "center"}, {"t": "say", "name": "呂布", "text": "……なぜ、立つ。なぜ、まだ——!"}, {"t": "narrate", "text": "奉先がもう一度、戟を構えた。さすがだ。わしの拾った刃だ。常人ならわし一吼えで腰を抜かす。だがこいつは退かぬ。女ひとりのために、父と呼んだ男に、もう一度穂先を向ける。"}, {"t": "narrate", "text": "——美しい刃だ。わしが世で唯一、惜しいと思った刃だ。"}, {"t": "say", "name": "董卓", "text": "奉先。最後に教えてやる"}, {"t": "narrate", "text": "わしは間合いを詰めた。あれの戟は速い。天下に並ぶ者なき速さだ。だがわしは、その速さを誰よりも知っている。育てたのはわしだ。"}, {"t": "say", "name": "董卓", "text": "女に惚れた獣は——強くなる。お前も、わしもな"}, {"t": "say", "name": "董卓", "text": "だが、惚れた女を分かち合えぬのも——獣だ"}, {"t": "sprite", "key": "lvbu_wounded", "pos": "center"}, {"t": "say", "name": "呂布", "text": "……貂、蝉……"}, {"t": "narrate", "text": "あれが最後に呼んだのは、わしの名ではなかった。父と呼んだ男の名でもなかった。あの女の名だった。"}, {"t": "narrate", "text": "わしの牛を盗もうとした目が、ゆっくりと光を失う。最強の刃が、わしの手の中で、砕けた。"}, {"t": "narrate", "text": "……わしが、砕いた。"}, {"t": "narrate", "text": "静かになった。王允は宝剣を取り落とした。李肅は腰を抜かして逃げた。百余の手勢は、一人また一人と松明を捨てて闇へ散った。"}, {"t": "narrate", "text": "わしは勝った。"}, {"t": "narrate", "text": "北掖門に立っているのは、わし一人だ。腕から血を流し、足元に最強の刃の屍を抱いて、わしは——天下を、握った。"}, {"t": "bg", "bg": "北掖門・静寂", "mood": "night"}, {"t": "narrate", "text": "笑え。"}, {"t": "narrate", "text": "わしは董卓だ。罠を踏み、罠を笑い、罠を仕掛けた者の骸を踏んで哄笑(こうしょう)する獣だ。今こそ笑う時だ。最大の敵を返り討ちにし、天下を手中にした夜だ。"}, {"t": "narrate", "text": "——笑え。"}, {"t": "narrate", "text": "出ない。"}, {"t": "narrate", "text": "喉の奥で、笑いが、つかえている。足元の刃が、邪魔をする。わしが拾い、わしが「子」と呼び、わしが砕いた、その刃が。"}, {"t": "narrate", "text": "初めてだった。奪って、何かが減ったと感じたのは。わしの掌の中はいつも増える一方だった。涼州も、洛陽も、天子も、この女も——すべて足し算だった。"}, {"t": "narrate", "text": "だが今宵、わしは引き算を知った。最強の刃という、一つきりの、もう二度と拾えぬものを。"}, {"t": "sprite", "key": "diaochan_killerlove", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "……太師"}, {"t": "narrate", "text": "来た。あの女だ。連環の計の刃。王允が研ぎ、呂布へ向け、わしへ向けた、生身の刃。"}, {"t": "narrate", "text": "あの女が、わしを見ている。血の海の中で、わしと、わしの足元の屍を、交互に見ている。"}, {"t": "say", "name": "貂蝉", "text": "呂将軍を……あなたは、本当に"}, {"t": "narrate", "text": "言葉が続かなかった。芝居なら、ここで泣くはずだ。鳳儀亭でそうしたように、香羅で涙を拭い、胸を指し、わしを指し、見事な水芸を打つはずだ。"}, {"t": "narrate", "text": "だが女は、泣かなかった。代わりに、瞳の奥で——怯えた。"}, {"t": "narrate", "text": "……怯えた?"}, {"t": "narrate", "text": "わしは、この女の怯えを初めて見た。動揺なら見た。芝居の涙なら飽きるほど見た。だが、この、底の知れぬ獣の井戸を覗き込んでしまった者の、本物の怯え——これは。"}, {"t": "narrate", "text": "信じたい。これは芝居ではない、と。本物の惚れた女が、わしの底の冷たさに初めて触れて、震えているのだと。"}, {"t": "narrate", "text": "だが——疑え。これもまた手か。最後の連環か。怯えてみせて、わしの最後の警戒を解く、止めの一手ではないのか。連環の計は、まだ続いているのではないか。"}, {"t": "narrate", "text": "いつもなら、わしはここで暴く。「お前の刃ごと暴いてやる」と、序(はじ)めにこの女へ言い放ったように。"}, {"t": "sprite", "key": "diaochan_flustered", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "……お腕が。血が"}, {"t": "narrate", "text": "女の指が、わしの傷に触れた。震えている。本物のように、震えている。"}, {"t": "say", "name": "董卓", "text": "……"}, {"t": "narrate", "text": "わしは——確かめなかった。"}, {"t": "narrate", "text": "暴かなかった。問わなかった。「それは芝居か、本物か」と、いつもの牙で噛みつかなかった。"}, {"t": "narrate", "text": "なぜか。簡単だ。もう、どうでもよくなったのだ。最強の刃を砕いた手で、わしはもう一つ、何かを失くしたらしい。「確かめたい」という、あの飢えを。"}, {"t": "narrate", "text": "俺(おれ)は——"}, {"t": "narrate", "text": "……わし、だ。わしは、確かめる気が起きぬだけだ。乱れてなどおらぬ。"}, {"t": "narrate", "text": "いや。乱れている。喪(うしな)ったものが、わしの一人称(おのれ)を、また一つ崩した。"}, {"t": "bg", "bg": "北掖門・暁近し", "mood": "dawn"}, {"t": "say", "name": "董卓", "text": "貂蝉"}, {"t": "say", "name": "貂蝉", "text": "……はい"}, {"t": "say", "name": "董卓", "text": "お前は、わしを選んだか"}, {"t": "sprite", "key": "diaochan_fakesmile", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "……はい。太師"}, {"t": "narrate", "text": "「はい」。"}, {"t": "narrate", "text": "この「はい」が、本物の惚れた女の返事なのか。それとも、最強の刃を失い独りになった獣に取り入る、最後の連環の一手なのか。"}, {"t": "narrate", "text": "わしには、もう、分からぬ。"}, {"t": "narrate", "text": "そして——分からぬまま、わしはこの「はい」を抱く。確かめずに、抱く。それがこの女に「落とされた」ということだ。落としたのは、わしのほうだったはずなのに。"}, {"t": "narrate", "text": "わしは天下を握った。力の正義は、勝った。奪うと言って奪い、殺すと言って殺し、最大の敵を返り討ちにし、女ひとりを手にした。すべてが、わしの宣言した通りになった。"}, {"t": "narrate", "text": "力こそ、正義だ。今宵、それは証明された。"}, {"t": "narrate", "text": "だが——証明された玉座は、こんなにも静かなのか。哄笑の出ぬ勝利が、こんなにも冷たいのか。"}, {"t": "narrate", "text": "足元には砕いた刃。腕には触れる女の指。そのどちらも、わしの掌の中にある。掌の中にあるのに——わしは初めて、何かが足りぬと感じている。喪うとは、こういうことか。獣が、最後に覚えた感情が、よりにもよって、これか。"}, {"t": "narrate", "text": "わしは火だ。何もかもを焚(や)き尽くす火だ。"}, {"t": "narrate", "text": "だが、焚き尽くした後の野には、灰と、わし一人と、本物か芝居か分からぬ女が一人、立っているだけだった。"}, {"t": "narrate", "text": "暁が来る。"}, {"t": "narrate", "text": "天下を握った獣の王が、たった一人、暁を待っている。"}, {"t": "narrate", "text": "隣に、女がいる。"}, {"t": "narrate", "text": "それでも、一人だ。"}, {"t": "fx", "fx": "blackout"}, {"t": "ending", "id": "KOOU", "title": "孤王"}, {"t": "ending", "id": "KOOU", "title": "【孤王】代償生存エンド"}], "FENTIAN": [{"t": "bg", "bg": "郿塢_太師居室・夜・燭火朱", "mood": "warm"}, {"t": "sprite", "key": "diaochan_base", "pos": "center"}, {"t": "narrate", "text": "連環の輪は、回りきった。"}, {"t": "narrate", "text": "わしはそれを知っていた。知っていて、火に手を突っ込む獣のように、この女を抱え込んだ。"}, {"t": "narrate", "text": "鳳儀亭で、わしは奉先に画戟を投げた。あの夜、貂蝉は荷花池の縁で泣き崩れ、奉先の腕の中で「老賊を恐れるなら、妾(わたし)に天日(おひさま)を仰ぐ日は来ぬ」と囁いた——あの台詞を、わしは柱の影で聞いていた。"}, {"t": "say", "name": "貂蝉", "text": "太師さま。……まだ、奉先さまのことを、お疑いですか"}, {"t": "narrate", "text": "疑う。当たり前だ。"}, {"t": "narrate", "text": "だが、こうして燭火の下で見上げてくる眦(まなじり)の濡れ方は、芝居にしては——惜しい。惜しいほど、よくできている。"}, {"t": "sprite", "key": "diaochan_tears", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "妾は、太師さまのものです。この胸を裂いて、中をご覧に入れたいくらい"}, {"t": "narrate", "text": "信じたい。"}, {"t": "narrate", "text": "いや——信じたい、と思わせるのが、この女の刃だ。"}, {"t": "narrate", "text": "早すぎるデレは疑え。序章でわしは己にそう言い聞かせた。なのに今、心の臓のどこかが、この涙を本物だと数えたがっている。"}, {"t": "narrate", "text": "……落とせなかった。今になって分かる。わしは火だ。火は何でも焼く。だがこの女だけは、焼けたふりをして、わしの内側に氷の刃を一本、ずっと差したままだった。"}, {"t": "narrate", "text": "わしは前者を選んだ。最後まで。"}, {"t": "sprite", "key": "diaochan_killerlove", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "……ふふ。こわいお方"}, {"t": "narrate", "text": "笑った。その笑いの底が、恋か殺意か、たぶんこの女自身にも分からぬまま——わしは、それでいいと思った。獣は、獲物が刃を隠していることを知って、なお食らうものだ。"}, {"t": "bg", "bg": "郿塢_書斎・燭一灯", "mood": "warm"}, {"t": "sprite", "key": "liju_remonstrate", "pos": "center"}, {"t": "narrate", "text": "あの男だけは、最後まで吼えていた。"}, {"t": "say", "name": "李儒", "text": "太師。貂蝉を、呂布に賜りなされ。絶纓の会の故事をお忘れか。臣下の無礼を許した王は、後に死力で報いられた。あの女一人を下げ渡せば、奉先は大恩に泣き、太師のために骨を砕きましょう"}, {"t": "narrate", "text": "一度目は、わしも「一理ある」と頷いた。だが翌朝、こいつはまた来た。"}, {"t": "say", "name": "李儒", "text": "女に惑わされなさるな。一門が、滅びまする"}, {"t": "narrate", "text": "わしは机を蹴った。"}, {"t": "say", "name": "董卓", "text": "では文優、貴様の妻を奉先にくれてやれるか。──二度言うてみよ。次は斬る"}, {"t": "sprite", "key": "liju_lament", "pos": "center"}, {"t": "narrate", "text": "李儒は退いた。戸口で、天井のさらに上の何かを仰いで、独り言のように吐き捨てた。"}, {"t": "say", "name": "李儒", "text": "……吾等(われら)、皆。婦人(おんな)の手にかかって、死ぬぞ"}, {"t": "narrate", "text": "慧眼。今となれば分かる。この国でただ一人、貂蝉を「女」ではなく、「一門を斬る刃」として正しく見ていたのは、わしが斬ると凄んだこの男だけだった。"}, {"t": "narrate", "text": "わしは火を見る目で女を見て、女を見る目で刃を見た。李儒だけが、刃を刃と見た。"}, {"t": "narrate", "text": "そして、その忠告を蹴った。蹴ったのは、わしだ。誰のせいでもない。"}, {"t": "bg", "bg": "郿塢_出立の門・払暁", "mood": "dawn"}, {"t": "sprite", "key": "lisu_base", "pos": "center"}, {"t": "say", "name": "李粛", "text": "天子、未央殿にて太師の禅(ゆず)りを望まれまする。受禅台、既に成りました"}, {"t": "narrate", "text": "禅位。天下が、ついにわしの掌に落ちてくる。"}, {"t": "narrate", "text": "わしは哄笑した。貂蝉を振り返った。"}, {"t": "say", "name": "貂蝉", "text": "おめでとうございます、太師さま。……妾を、貴妃に"}, {"t": "say", "name": "董卓", "text": "おう。貴妃にしてやる。火の傍らの、わしの貴妃よ"}, {"t": "narrate", "text": "あの時、貂蝉は微笑んでいた。"}, {"t": "narrate", "text": "今になって思う。あれは——已(すで)に裏を知った者の笑みだった。わしが受禅台へ昇る道の先に、何が待つか。この女は、もう知っていた。"}, {"t": "narrate", "text": "……それでも、あの笑みが、わしを送り出す本物の名残惜しさを、一滴も含んでいなかったと、誰に言い切れる。誰にも言い切れぬ。死ぬ今になっても、言い切れぬ。"}, {"t": "fx", "fx": "cutin"}, {"t": "narrate", "text": "車輪が、折れた。馬が手綱を食い千切った。"}, {"t": "narrate", "text": "道端の青袍白巾の道人が、竿に布を垂らしていた。両端に、「口」の字が二つ。──呂、と読めた。"}, {"t": "narrate", "text": "童(わらべ)が歌っていた。"}, {"t": "say", "name": "童子たち", "text": "千里草、何ぞ青青たる。十日の上(かみ)、生を得ず——"}, {"t": "narrate", "text": "千里草、十日上。重ねれば「董卓」。生を得ず。"}, {"t": "narrate", "text": "凶兆だと、誰かが囁いた。わしは鼻で笑った。獣は前兆では止まらぬ。止まれぬ。前へ進むことしか知らぬから、獣なのだ。"}, {"t": "bg", "bg": "北掖門・払暁の薄明", "mood": "dawn"}, {"t": "fx", "fx": "blackout"}, {"t": "narrate", "text": "殿門。"}, {"t": "fx", "fx": "flash"}, {"t": "sprite", "key": "wangyun_resolved", "pos": "center"}, {"t": "say", "name": "王允", "text": "反賊、ここに至れり! 武士(つわもの)は、いずこ!"}, {"t": "fx", "fx": "cutin"}, {"t": "narrate", "text": "両側から、湧いた。百を超える戟と槊が、いっせいにわしを突いた。"}, {"t": "narrate", "text": "──通らぬ。"}, {"t": "narrate", "text": "わしは鎧を着込んでいた。火を統べる男が、丸腰で天下を受けに行くものか。切先は鉄に弾かれ、火花を散らした。"}, {"t": "say", "name": "董卓", "text": "ぬるいわ! 貴様らの刃は、ぬるい!"}, {"t": "narrate", "text": "哄笑した。腐れ貴族どもが、束になって、ようやくこれか。制度の蔭でしか牙を剥けぬ羊どもが。"}, {"t": "narrate", "text": "だが一本が、腕の隙間を縫った。血が噴いた。車の縁が傾ぎ、わしは地に落ちた。"}, {"t": "narrate", "text": "鎧の重みが、初めて己の重みになった。"}, {"t": "say", "name": "董卓", "text": "吾が子、奉先(ほうせん)は——いずこ! 奉先!"}, {"t": "narrate", "text": "呼んだ。わしは、あの男を呼んだ。"}, {"t": "narrate", "text": "わしが拾い、わしが父と呼ばせ、わしが黄金を与えた、わしの子を。"}, {"t": "narrate", "text": "影が、車の後ろから立った。"}, {"t": "sprite", "key": "lvbu_cold", "pos": "center"}, {"t": "narrate", "text": "逆光で、顔が見えぬ。見えぬのに、わしには分かった。あの目の奥に灯っているのは、忠でも孝でもない。"}, {"t": "narrate", "text": "女だ。"}, {"t": "say", "name": "呂布", "text": "詔(みことのり)あり。──賊を、討つ"}, {"t": "fx", "fx": "flash"}, {"t": "narrate", "text": "戟が、咽喉(のど)を、貫いた。"}, {"t": "narrate", "text": "……あつい。"}, {"t": "narrate", "text": "火を統べてきたわしが、今、己の咽喉から噴く己の熱で、初めて火傷をした。"}, {"t": "narrate", "text": "視界の端に、貂蝉は、いない。来るはずもない。あの女の手は最後まで汚れぬ。刃は己の喉か、奉先の戟。わしを刺すのは、いつも別の手だ。それが連環。それが、あの女の——道理(てだて)。"}, {"t": "narrate", "text": "——なあ。貂蝉。"}, {"t": "narrate", "text": "俺は。"}, {"t": "narrate", "text": "……わし、ではない。俺、と言いかけた。今わの際に、わしの自我は、また乱れた。お前にだけは、最後まで、乱された。"}, {"t": "narrate", "text": "あのデレは、本物だったか。殺すための嘘だったか。"}, {"t": "narrate", "text": "答えは——来ない。来ないことが、お前の答えだ。お前は、宙吊りのまま、わしを置いていく。"}, {"t": "narrate", "text": "それでよい。獣は、獲物に化かされて死ぬのが、性に合っている。"}, {"t": "say", "name": "董卓", "text": "……は、はは。ははははは——!"}, {"t": "narrate", "text": "わしは、笑った。荒ぶる獅子のまま、貴族どもの卑劣を呪い、哄笑して——"}, {"t": "fx", "fx": "blackout"}, {"t": "sprite", "key": "lisu_kokuhaku", "pos": "center"}, {"t": "narrate", "text": "李肅の刃が、わしの首を、胴から断った。"}, {"t": "say", "name": "呂布", "text": "詔を奉じ、賊臣董卓を討てり。──其の余は、問わず"}, {"t": "bg", "bg": "長安市曹・昼・晒し首", "mood": "warm"}, {"t": "sprite", "key": "lvbu_base", "pos": "center"}, {"t": "say", "name": "呂布", "text": "董卓を助け、虐(ぎゃく)を為したは——皆、李儒なり"}, {"t": "sprite", "key": "liju_death", "pos": "center"}, {"t": "narrate", "text": "文優。"}, {"t": "narrate", "text": "貴様の慧眼は、最後まで誰にも信じられず、貴様自身を縛る縄になった。"}, {"t": "say", "name": "李儒", "text": "…………"}, {"t": "narrate", "text": "こいつは、もう何も言わなかった。「だから申したでしょう」とすら。天を仰いだあの嘆きが、こいつの最後の言葉だった。"}, {"t": "narrate", "text": "家奴に売られ、王允の前に引き出され、市曹で斬られた。「われら皆、婦人の手にかかって死ぬぞ」——その「われら」に、こいつは律儀に己を入れていた。入れて、死んだ。連座。わしの女狂いの、連座だ。"}, {"t": "bg", "bg": "長安大通り・董卓の屍・晒し", "mood": "warm"}, {"t": "narrate", "text": "屍は、大通りに晒された。"}, {"t": "narrate", "text": "わしは肥えていた。火をくべ過ぎた炉のように、よく肥えていた。"}, {"t": "narrate", "text": "番人が、わしの臍(ほぞ)に、灯心を挿した。火を点した。"}, {"t": "narrate", "text": "脂が、燃えた。わしの脂が、灯になった。夜を徹して、地に溢れた。"}, {"t": "narrate", "text": "火を統べた男が、最後は己が脂で、地を照らす灯になった。笑える。──いや、笑えぬか。笑うのは、もう口がない。"}, {"t": "narrate", "text": "民が来た。わしの首を蹴り、投げ、屍を踏んだ。涼州で兵を飢えさせなかった男の屍を、長安の民は、嬉々として踏んだ。"}, {"t": "narrate", "text": "力は、力に殺されたのではない。"}, {"t": "narrate", "text": "陰謀に、制度に、貴族どもの卑劣の網に——殺された。火は、水で消されたのではない。蓋(ふた)で、息を止められた。"}, {"t": "bg", "bg": "同・夜・燃える臍火の灯", "mood": "night"}, {"t": "sprite", "key": "caiyong_grief", "pos": "center"}, {"t": "narrate", "text": "ただ一人。"}, {"t": "narrate", "text": "侍中・蔡邕(さいよう)だけが、わしの屍に伏して、哭(な)いた。"}, {"t": "say", "name": "蔡邕", "text": "……太師。知遇の、恩が、ござりました……"}, {"t": "narrate", "text": "知遇。わしがこの男の才を取り立てた、それだけのこと。"}, {"t": "narrate", "text": "万人が踏むわしの屍に、ただ一人、涙を落とす者がいた。そのことに、わしの何が許されるわけでもない。蔡邕とて、すぐに王允に捕らえられ、獄で縊(くび)れて死ぬ。わしに泣いた、その咎で。"}, {"t": "narrate", "text": "わしの周りは、こうだ。わしを正しく見た者から、わしに泣いた者から、順に死んでいく。"}, {"t": "bg", "bg": "長安・払暁／臍火、燃え尽きる", "mood": "dawn"}, {"t": "narrate", "text": "万人が、わしの屍を踏み越えて通り過ぎていく。誰一人、わしを総括しない。"}, {"t": "narrate", "text": "それでいい。わしを総括するな。わしは総括される器ではない。"}, {"t": "narrate", "text": "火だった。火に意味を求めるな。火は燃え、燃え尽き、灯になり、踏まれた。それだけだ。"}, {"t": "say", "name": "童子たち", "text": "千里草、何ぞ青青たる。十日の上、生を得ず——"}, {"t": "narrate", "text": "千里草、青青。"}, {"t": "narrate", "text": "──落とせなかった。"}, {"t": "narrate", "text": "わしは、あの女を落とせなかった。あのデレが本物か嘘か、わしは知らぬまま死んだ。たぶん、嘘だった。殺すためのデレだった。早すぎるデレは疑え——その一行を、わしは正しく疑い、正しく食らい、正しく死んだ。"}, {"t": "narrate", "text": "それでも。"}, {"t": "narrate", "text": "死の間際、咽喉を貫かれて、わしの自我が「わし」から「俺」へ漏れた、あの一瞬だけは。"}, {"t": "narrate", "text": "……あの女に、本当に、掴まれていたのかもしれぬ。"}, {"t": "fx", "fx": "blackout"}, {"t": "narrate", "text": "焚天。"}, {"t": "narrate", "text": "天を焚いた火は、灯一つ残して、消えた。"}, {"t": "ending", "id": "FENTIAN", "title": "【焚天】史実死エンド"}, {"t": "ending", "id": "FENTIAN", "title": "【焚天】史実死エンド"}], "RAKKA": [{"t": "bg", "bg": "北掖門・未明（薄藍の闇、霜柱、宮門の影が長い）", "mood": "dawn"}, {"t": "fx", "fx": "fade"}, {"t": "narrate", "text": "受禅台が築かれた、と李肅は言った。天子がこのわしに位を譲ると。未央殿で禅(ゆず)りを受けよ、と。"}, {"t": "narrate", "text": "馬車の車輪が一度折れ、馬が手綱を食いちぎった。郿塢を出てから、童(わらべ)が妙な歌をうたっていた。「千里草、何ぞ青青たる──十日の上、生を得ず」と。"}, {"t": "narrate", "text": "……ふん。凶兆を数える齢でもない。わしは火だ。火に祟りを説く者がどこにいる。"}, {"t": "sprite", "key": "diaochan_fakesmile", "pos": "right"}, {"t": "say", "name": "貂蝉", "text": "太師さま。お顔が、こわばっておいでですよ"}, {"t": "narrate", "text": "貂蝉が、わしの腕に身を寄せてくる。鬢の香が冷えた朝気に溶けて、わしの首筋へ昇ってくる。"}, {"t": "narrate", "text": "この女は、知っている。今日わしが帝位を踏むことも、貴妃にしてやると言ったことも、もう聞かされている。それでこの、蕩(とろ)けるような顔だ。已に裏を知って、なお喜んでみせる顔だ。"}, {"t": "say", "name": "貂蝉", "text": "貴妃に、してくださるのでしょう？　……ねえ。妾を、本当に"}, {"t": "narrate", "text": "信じたい。"}, {"t": "narrate", "text": "──と、思った刹那、舌打ちが出た。わし自身への舌打ちだ。"}, {"t": "narrate", "text": "この女のデレを、わしは何度疑い、何度ほどき、何度それでも欲したか。芝居か。本物か。今この瞬間、しなだれてくる重みすら、わしを未央殿の刃の前へ押し出すための、計の最後の一押しではないのか。"}, {"t": "narrate", "text": "だが。李儒の声が耳の奥で鳴る。「われら皆、女の手にかかって死ぬぞ」──あの男の慧眼を、わしは二度蹴った。三度目はもう、聞かぬと決めていた。"}, {"t": "bg", "bg": "未央殿・北掖門前（宝剣を提げた群臣の影、白布、戟槊の鈍い光）", "mood": "cool"}, {"t": "fx", "fx": "blackout"}, {"t": "fx", "fx": "cutin"}, {"t": "sprite", "key": "wangyun_desperate", "pos": "center"}, {"t": "say", "name": "王允", "text": "反賊、ここに至れり──武士は、いずこか！"}, {"t": "fx", "fx": "flash"}, {"t": "narrate", "text": "来た。"}, {"t": "narrate", "text": "笑った。腹の底から笑った。罠か、と過(よ)ぎりはした。だが──読み切れなんだ。李儒の諫言を二度蹴ったわしには、王允の糸の全貌が、ついぞ見えなんだ。見えぬまま、火は前へ出る。これが火の生き方よ。"}, {"t": "narrate", "text": "戟が降る。槊が突き来る。だがわしの内には鎧がある。刃は鱗を弾き、わしの腕を一筋裂いただけだ。"}, {"t": "sprite", "key": "dongzhuo_fury", "pos": "center"}, {"t": "say", "name": "董卓", "text": "ぬるいわ……っ、その程度で、この火が消せるか！"}, {"t": "narrate", "text": "車を蹴って降り立つ。血が肘を伝う。痛みなど祭りの太鼓だ。"}, {"t": "narrate", "text": "わしは吼えた。この場でただ一人、わしを討たぬ男の名を。"}, {"t": "say", "name": "董卓", "text": "吾が子・奉先(ほうせん)は、いずこかッ！"}, {"t": "sprite", "key": "lvbu_cold", "pos": "center"}, {"t": "narrate", "text": "……いた。"}, {"t": "narrate", "text": "車の後ろ。逆光の中に、方天画戟を構えた、わしの飛将。"}, {"t": "say", "name": "呂布", "text": "詔(みことのり)あり──賊を、討つ"}, {"t": "narrate", "text": "奉先。"}, {"t": "narrate", "text": "その一言で、わしは全てを読んだ。貂蝉だ。鳳儀亭で、この男の喉に火を点(つ)けたのは。わしが二度蹴った李儒の諫言の、その正体が、今この戟の切先に立っている。"}, {"t": "narrate", "text": "戟が、来る。"}, {"t": "sprite", "key": "diaochan_killerlove", "pos": "center"}, {"t": "narrate", "text": "白い。"}, {"t": "narrate", "text": "白いものが、わしと戟の間へ、飛び込んだ。"}, {"t": "narrate", "text": "貂蝉だ。"}, {"t": "fx", "fx": "flash"}, {"t": "say", "name": "呂布", "text": "──ッ、貂、蝉……！？"}, {"t": "narrate", "text": "時が、戻った。音が、戻った。"}, {"t": "narrate", "text": "方天画戟の穂先は、わしの咽喉(のど)へ届く寸前で──女の背を、貫いていた。"}, {"t": "narrate", "text": "貂蝉が、わしの胸へ倒れ込んでくる。さっきと同じ、しなだれる重み。だが今度のそれは、香ではなく、血の匂いがした。"}, {"t": "narrate", "text": "呂布が戟を捨てた。膝が折れる音がした。あの飛将が、人形のように崩れていく。だがわしの目には、もう奴は映らぬ。"}, {"t": "narrate", "text": "わしの腕の中に、堕ちた花が一輪、ある。"}, {"t": "bg", "bg": "北掖門前・朝陽が差し始める（白布に滲む赤、霜が溶ける）", "mood": "dawn"}, {"t": "sprite", "key": "diaochan_tears", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "……ねえ、太師、さま"}, {"t": "narrate", "text": "抱きとめた。膝をつき、女を胸に抱いた。鎧の鱗が女の柔い背を傷つけぬよう──ふん、何を気遣っている。獣のすることか、これが。"}, {"t": "say", "name": "貂蝉", "text": "重い、でしょう。……妾、いつも、芝居の重みで、しなだれて、いたから"}, {"t": "say", "name": "董卓", "text": "喋るな。穴が開く"}, {"t": "say", "name": "貂蝉", "text": "もう、開いて、ますよ"}, {"t": "narrate", "text": "笑った。血を吐きながら、この女、笑いおった。"}, {"t": "sprite", "key": "diaochan_truesmile", "pos": "center"}, {"t": "narrate", "text": "わしは、この笑みを何度見たか。作り笑い。妖艶な誘い。見透かされて冷える嘲り。──だが今、唇の端に咲いているこれは、わしの知らぬ顔だった。"}, {"t": "narrate", "text": "素顔だ。"}, {"t": "narrate", "text": "十六の、ただの女の。"}, {"t": "say", "name": "貂蝉", "text": "太師さま。妾はね……王允さまの、刃でした。あなたを、殺すために、磨かれた"}, {"t": "say", "name": "董卓", "text": "知っておるわ。最初から"}, {"t": "say", "name": "貂蝉", "text": "ふふ……知ってて、欲しがった。馬鹿な、お人"}, {"t": "narrate", "text": "女の手が、わしの頬へ伸びる。血で濡れた指が、わしの髭をたどる。"}, {"t": "narrate", "text": "媚びではない。掴むためのデレでもない。掴むべきわしは、もう女の手の中で死にかけている、この女自身の方なのに。"}, {"t": "say", "name": "貂蝉", "text": "ずっと、わからなかった。妾のこの、しなだれが……あなたを油断させる、武器なのか。それとも──"}, {"t": "narrate", "text": "そこで女は咳(む)せた。血が、わしの胸甲に散った。"}, {"t": "say", "name": "貂蝉", "text": "……本物の、惚れ、なのか。妾にも、わからなかったの"}, {"t": "narrate", "text": "──わしにもだ。"}, {"t": "narrate", "text": "この刻のために、わしはどれほどこの女の真贋を量ったか。早すぎるデレを疑え、と己に言い聞かせ。涙を芝居と切り捨て。しなだれを罠と読み。それでも、欲した。"}, {"t": "say", "name": "貂蝉", "text": "でもね。今、わかった"}, {"t": "sprite", "key": "diaochan_flustered", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "妾、あなたと戟の間に……勝手に、体が動いたの。計でも、命でもなく。妾の、体が"}, {"t": "say", "name": "貂蝉", "text": "これで……証明、できたでしょう。妾のデレが、芝居じゃ、なかったって"}, {"t": "narrate", "text": "心臓を、掴まれた。"}, {"t": "narrate", "text": "いや──掴まれたのではない。掴んだのだ、ついに、わしがこの女の心を。落とすと言った。獲ると言った。そして今、確かに獲った。"}, {"t": "narrate", "text": "……だが。獲ったと思うこの一瞬すら、女が死にざまで仕掛けた、最後のデレでないと、誰が言える。──いや。問うな。今だけは、問うな。"}, {"t": "narrate", "text": "……獲った手の中で、それは事切れようとしている。"}, {"t": "say", "name": "董卓", "text": "……っ、おい"}, {"t": "narrate", "text": "わしは、わしの声が裂けるのを聞いた。"}, {"t": "say", "name": "董卓", "text": "貂蝉。おい、貂蝉。死ぬな。死ぬなと、わしが──"}, {"t": "narrate", "text": "俺が、言っている。"}, {"t": "narrate", "text": "……わし、ではない。「俺」が。鳳儀亭で一度だけ漏れて、わしが己を律して封じたあの一人称が、今、堰を切って溢れている。乱れている。それも、もう、どうでもいい。"}, {"t": "say", "name": "董卓", "text": "俺が、貴妃にしてやると言った。天下を、お前の足元に敷くと。聞いておったろうがッ!!"}, {"t": "narrate", "text": "火が、吼えた。"}, {"t": "narrate", "text": "涼州で羌を屈服させたときも、洛陽を焼いたときも、わしは一度も誰かの名を呼んで吼えたことなどない。奪うときは奪うと言い、殺すときは殺すと言ってきた。欲しいものは、力で獲ってきた。獲れぬものなど、無かった。"}, {"t": "narrate", "text": "なのに今、わしは、たった一人の女の名を呼んで、獣のように吼えている。"}, {"t": "narrate", "text": "力で、引き止められぬものがある。生まれて初めて、火の届かぬものを知った。"}, {"t": "sprite", "key": "diaochan_tears", "pos": "center"}, {"t": "say", "name": "貂蝉", "text": "……あぁ、いい、お声。……その『俺』が、聞きたかった"}, {"t": "say", "name": "貂蝉", "text": "太師さまの……ほんとうの、声"}, {"t": "narrate", "text": "女の指が、わしの頬から、ずり落ちた。"}, {"t": "narrate", "text": "落ちる途中で、わしはその手を掴んだ。掴んで、己の頬へ押し戻した。冷えていく。香が、血の下から、最後にひとすじ立ちのぼった。鳳儀亭で嗅いだ、あの香だ。"}, {"t": "say", "name": "貂蝉", "text": "ねえ……次に生まれたら。妾を、殺す女じゃ、なくて……"}, {"t": "say", "name": "貂蝉", "text": "ただの、女として……落としてね。太師さま"}, {"t": "narrate", "text": "答えを、わしは持っていた。"}, {"t": "narrate", "text": "落とす、と。次など待たぬ、今ここで落とし直してやる、と。"}, {"t": "narrate", "text": "だが女は、その答えを聞く前に、わしの腕の中で軽くなった。花が枝を離れる、あの軽さで。"}, {"t": "bg", "bg": "北掖門前・完全な朝（白い光、屍を踏む民、晒される影 ── だが董卓の視界はぼやけている）", "mood": "dawn"}, {"t": "narrate", "text": "王允が何か叫んでいる。李肅が剣を提げて近づいてくる。わしの首を獲りに来るのだろう。"}, {"t": "narrate", "text": "……来い。獲れるものなら。"}, {"t": "narrate", "text": "だが奴らの戟は、もうわしの胸甲を貫けなかった。鎧のせいではない。この女が、わしと刃の間に、もう一枚、最期の鱗を成して死んだからだ。落とした花が、散ることでしか、わしを生かせなかった。"}, {"t": "narrate", "text": "わしは、生き延びる。"}, {"t": "narrate", "text": "火は消えなかった。涼州の獅子は、なお荒ぶる。天下は、まだわしの掌(て)の中にある。"}, {"t": "narrate", "text": "──だが、その掌は、空(から)だ。"}, {"t": "narrate", "text": "獲ると誓った心を、確かに獲った。獲った瞬間に、喪った。"}, {"t": "sprite", "key": "diaochan_tears", "pos": "center"}, {"t": "narrate", "text": "わしは、立たぬ。"}, {"t": "narrate", "text": "朝陽が霜を溶かし、白布を赤く濡らし、民が屍を踏み越えていく音の中で、わしは膝をつき、たった一輪の落花を抱いたまま、しばし、火であることを、やめた。"}, {"t": "say", "name": "董卓", "text": "……貂蝉"}, {"t": "narrate", "text": "もう、しなだれてはこない重みを、わしは、いつまでも、抱いていた。"}, {"t": "fx", "fx": "blackout"}, {"t": "ending", "id": "RAKKA", "title": "【落花】悲劇恋愛エンド"}]};
